{
  "name": "ScormGenAI",
  "description": "An AI-powered course authoring tool. It generates course outlines, lesson content, and uses Gemini Nano to create educational illustrations on the fly."
}

export interface Lesson {
  id: string;
  title: string;
  content?: string;
  imageUrl?: string;
  imagePrompt?: string;
  isLoading?: boolean;
}

export interface Module {
  id: string;
  title: string;
  lessons: Lesson[];
}

export interface Course {
  id: string;
  title: string;
  description: string;
  modules: Module[];
  language: string;
}

export enum GenerationStep {
  IDLE,
  OUTLINE,
  CONTENT,
  COMPLETED
}

import { GoogleGenAI, Type } from "@google/genai";
import { Course, Module, Lesson } from "../types";

const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean up JSON string if the model adds backticks
const cleanJson = (text: string) => {
  return text.replace(/^```json\s*/, "").replace(/\s*```$/, "");
};

/**
 * Generates a course outline based on a topic.
 * Uses gemini-3-flash-preview for fast structural reasoning.
 */
export const generateCourseOutline = async (topic: string, language: string = 'Portuguese'): Promise<Course> => {
  const ai = getAiClient();

  const prompt = `Create a detailed course outline for a SCORM training course about: "${topic}". 
  The output must be in ${language}.
  The course should have 2-3 modules, and each module should have 2-3 lessons.
  Provide a short description for the course.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          modules: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                lessons: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      title: { type: Type.STRING },
                      imagePrompt: { type: Type.STRING, description: "A detailed visual description to generate an educational image for this lesson." }
                    },
                    required: ["title", "imagePrompt"]
                  }
                }
              },
              required: ["title", "lessons"]
            }
          }
        },
        required: ["title", "description", "modules"]
      }
    }
  });

  const rawText = response.text || "{}";
  const data = JSON.parse(cleanJson(rawText));

  // Transform into internal types with IDs
  const course: Course = {
    id: crypto.randomUUID(),
    title: data.title,
    description: data.description,
    language: language,
    modules: data.modules.map((m: any) => ({
      id: crypto.randomUUID(),
      title: m.title,
      lessons: m.lessons.map((l: any) => ({
        id: crypto.randomUUID(),
        title: l.title,
        imagePrompt: l.imagePrompt,
        content: "", // Content generated later on demand
      }))
    }))
  };

  return course;
};

/**
 * Generates the text content for a specific lesson.
 */
export const generateLessonContent = async (lessonTitle: string, courseTitle: string, language: string): Promise<string> => {
  const ai = getAiClient();
  const prompt = `Write a comprehensive educational lesson in Markdown format for the lesson "${lessonTitle}" which is part of the course "${courseTitle}". 
  Language: ${language}.
  Structure:
  - Introduction
  - Key Concepts (bullet points)
  - Detailed Explanation
  - Summary/Takeaway
  Keep it engaging and suitable for e-learning (SCORM). Do not include images in the markdown, only text.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
  });

  return response.text || "Failed to generate content.";
};

/**
 * Generates an educational image using the Nano Banana model (gemini-2.5-flash-image).
 */
export const generateLessonImage = async (imagePrompt: string): Promise<string | undefined> => {
  const ai = getAiClient();

  // Refine prompt for educational style
  const refinedPrompt = `Educational illustration, flat design, clean vector style, easy to understand. ${imagePrompt}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: {
        parts: [{ text: refinedPrompt }]
      }
    });

    // Extract image from parts
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Image generation failed:", error);
    return undefined;
  }

  return undefined;
};

import React, { useState, useCallback } from 'react';
import { Course, Module, Lesson, GenerationStep } from '../types';
import * as GeminiService from '../services/geminiService';

// SVG Icons
const SparklesIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
);

const BookIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20"/><path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"/></svg>
);

const ImageIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="18" height="18" x="3" y="3" rx="2" ry="2"/><circle cx="9" cy="9" r="2"/><path d="m21 15-3.086-3.086a2 2 0 0 0-2.828 0L6 21"/></svg>
);

const DownloadIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
);

interface CourseBuilderProps {}

const CourseBuilder: React.FC<CourseBuilderProps> = () => {
  const [topic, setTopic] = useState('');
  const [loading, setLoading] = useState(false);
  const [course, setCourse] = useState<Course | null>(null);
  const [activeLessonId, setActiveLessonId] = useState<string | null>(null);
  const [generatingImageId, setGeneratingImageId] = useState<string | null>(null);

  const handleCreateCourse = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topic.trim()) return;

    setLoading(true);
    try {
      const generatedCourse = await GeminiService.generateCourseOutline(topic);
      setCourse(generatedCourse);

      // Select first lesson by default
      if (generatedCourse.modules.length > 0 && generatedCourse.modules[0].lessons.length > 0) {
        setActiveLessonId(generatedCourse.modules[0].lessons[0].id);
        // Trigger content generation for the first lesson immediately
        fetchLessonContent(generatedCourse.modules[0].lessons[0], generatedCourse.title);
      }
    } catch (error) {
      console.error("Error creating course:", error);
      alert("Failed to create course structure. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const fetchLessonContent = async (lesson: Lesson, courseTitle: string) => {
    // If content exists, don't regenerate
    if (lesson.content) return;

    updateLesson(lesson.id, { isLoading: true });

    try {
      const content = await GeminiService.generateLessonContent(lesson.title, courseTitle, 'Portuguese');
      updateLesson(lesson.id, { content, isLoading: false });
    } catch (error) {
      console.error("Error fetching content:", error);
      updateLesson(lesson.id, { isLoading: false, content: "Error loading content." });
    }
  };

  const generateImageForLesson = async (lesson: Lesson) => {
    if (!lesson.imagePrompt) return;
    setGeneratingImageId(lesson.id);

    try {
      const imageUrl = await GeminiService.generateLessonImage(lesson.imagePrompt);
      if (imageUrl) {
        updateLesson(lesson.id, { imageUrl });
      }
    } catch (error) {
      console.error("Error generating image:", error);
    } finally {
      setGeneratingImageId(null);
    }
  };

  const updateLesson = (lessonId: string, updates: Partial<Lesson>) => {
    setCourse(prev => {
      if (!prev) return null;
      const newModules = prev.modules.map(mod => ({
        ...mod,
        lessons: mod.lessons.map(les => 
          les.id === lessonId ? { ...les, ...updates } : les
        )
      }));
      return { ...prev, modules: newModules };
    });
  };

  const handleLessonSelect = (lesson: Lesson) => {
    setActiveLessonId(lesson.id);
    if (!lesson.content && course) {
      fetchLessonContent(lesson, course.title);
    }
  };

  const getActiveLesson = () => {
    if (!course) return null;
    for (const mod of course.modules) {
      for (const les of mod.lessons) {
        if (les.id === activeLessonId) return les;
      }
    }
    return null;
  };

  const activeLesson = getActiveLesson();

  // Simulated SCORM Export
  const handleExport = () => {
    if (!course || !activeLesson) return;

    // Create a simple HTML blob representing a "SCORM Package"
    const htmlContent = `
    <!DOCTYPE html>
    <html>
    <head><title>${activeLesson.title}</title></head>
    <body style="font-family: sans-serif; max-width: 800px; margin: 0 auto; padding: 20px;">
      <h1>${activeLesson.title}</h1>
      ${activeLesson.imageUrl ? `<img src="${activeLesson.imageUrl}" style="max-width: 100%; border-radius: 8px; margin-bottom: 20px;">` : ''}
      <div>${activeLesson.content?.replace(/\n/g, '<br>')}</div>
    </body>
    </html>
    `;

    const blob = new Blob([htmlContent], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `scorm_package_${activeLesson.title.replace(/\s+/g, '_')}.html`;
    a.click();
  };

  if (!course) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-gradient-to-br from-indigo-500 to-purple-600 p-4">
        <div className="bg-white rounded-2xl shadow-2xl p-8 max-w-md w-full">
          <div className="flex items-center justify-center mb-6">
            <div className="bg-indigo-100 p-3 rounded-full">
              <SparklesIcon />
            </div>
          </div>
          <h1 className="text-3xl font-bold text-center text-slate-800 mb-2">ScormGenAI</h1>
          <p className="text-center text-slate-500 mb-8">
            Create AI-powered courses with auto-generated structure and visual aids using Gemini Nano.
          </p>

          <form onSubmit={handleCreateCourse} className="space-y-4">
            <div>
              <label htmlFor="topic" className="block text-sm font-medium text-slate-700 mb-1">
                What do you want to teach?
              </label>
              <input
                type="text"
                id="topic"
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                placeholder="e.g., Workplace Safety, Java Programming..."
                className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-colors"
                disabled={loading}
              />
            </div>
            <button
              type="submit"
              disabled={loading || !topic}
              className={`w-full flex items-center justify-center py-3 px-4 rounded-lg text-white font-medium transition-all ${
                loading || !topic 
                  ? 'bg-indigo-300 cursor-not-allowed' 
                  : 'bg-indigo-600 hover:bg-indigo-700 shadow-lg hover:shadow-indigo-500/30'
              }`}
            >
              {loading ? (
                <>
                  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Generating Structure...
                </>
              ) : (
                <>
                  <SparklesIcon />
                  <span className="ml-2">Generate Course</span>
                </>
              )}
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar - Course Navigation */}
      <aside className="w-80 bg-white border-r border-slate-200 flex flex-col h-full z-10">
        <div className="p-5 border-b border-slate-100">
          <h2 className="font-bold text-lg text-slate-800 line-clamp-1">{course.title}</h2>
          <p className="text-xs text-slate-500 mt-1 line-clamp-2">{course.description}</p>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-6">
          {course.modules.map((module, mIdx) => (
            <div key={module.id}>
              <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 pl-2">
                Module {mIdx + 1}: {module.title}
              </h3>
              <div className="space-y-1">
                {module.lessons.map((lesson) => (
                  <button
                    key={lesson.id}
                    onClick={() => handleLessonSelect(lesson)}
                    className={`w-full text-left px-3 py-2 rounded-md text-sm transition-colors flex items-center group ${
                      activeLessonId === lesson.id
                        ? 'bg-indigo-50 text-indigo-700 font-medium'
                        : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900'
                    }`}
                  >
                    <BookIcon />
                    <span className="ml-3 truncate">{lesson.title}</span>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>

        <div className="p-4 border-t border-slate-100 bg-slate-50">
          <button 
            onClick={handleExport}
            className="w-full flex items-center justify-center py-2 px-4 border border-slate-300 rounded-md text-sm font-medium text-slate-700 bg-white hover:bg-slate-50 transition-colors"
          >
            <DownloadIcon />
            <span className="ml-2">Export SCORM Package</span>
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto bg-white/50 relative">
        {activeLesson ? (
          <div className="max-w-4xl mx-auto px-8 py-12">

            {/* Header */}
            <div className="mb-8 border-b border-slate-100 pb-8">
              <h1 className="text-4xl font-extrabold text-slate-900 mb-4 tracking-tight">
                {activeLesson.title}
              </h1>
              <div className="flex items-center gap-2">
                 <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                   AI Generated
                 </span>
                 <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                   {course.language}
                 </span>
              </div>
            </div>

            {/* AI Image Section */}
            <div className="mb-10 bg-slate-50 rounded-xl border border-slate-100 p-1 overflow-hidden">
               {activeLesson.imageUrl ? (
                 <div className="relative group">
                   <img 
                    src={activeLesson.imageUrl} 
                    alt="AI Generated Educational Content" 
                    className="w-full h-auto rounded-lg object-cover max-h-[400px]"
                   />
                   <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors rounded-lg pointer-events-none" />
                 </div>
               ) : (
                 <div className="h-64 flex flex-col items-center justify-center bg-slate-100 rounded-lg border-2 border-dashed border-slate-300 p-6 text-center">
                   {generatingImageId === activeLesson.id ? (
                     <div className="flex flex-col items-center animate-pulse">
                       <div className="w-12 h-12 bg-indigo-200 rounded-full mb-3" />
                       <p className="text-slate-500 font-medium">Generating Nano Banana visualization...</p>
                       <p className="text-xs text-slate-400 mt-1">Using gemini-2.5-flash-image</p>
                     </div>
                   ) : (
                     <>
                        <div className="bg-white p-3 rounded-full shadow-sm mb-3">
                          <ImageIcon />
                        </div>
                        <h3 className="text-sm font-medium text-slate-900">No Visualization Yet</h3>
                        <p className="text-xs text-slate-500 mt-1 mb-4 max-w-sm">
                          Enhance this lesson with an AI-generated image tailored to explain the concepts.
                        </p>
                        <button
                          onClick={() => generateImageForLesson(activeLesson)}
                          className="px-4 py-2 bg-indigo-600 text-white text-sm rounded-md shadow-sm hover:bg-indigo-700 transition-all flex items-center"
                        >
                          <SparklesIcon />
                          <span className="ml-2">Generate Image (Nano Banana)</span>
                        </button>
                     </>
                   )}
                 </div>
               )}
            </div>

            {/* Lesson Content */}
            <div className="prose prose-slate lg:prose-lg max-w-none">
              {activeLesson.isLoading ? (
                <div className="space-y-4 animate-pulse">
                  <div className="h-4 bg-slate-200 rounded w-3/4"></div>
                  <div className="h-4 bg-slate-200 rounded w-full"></div>
                  <div className="h-4 bg-slate-200 rounded w-5/6"></div>
                  <div className="h-32 bg-slate-200 rounded w-full mt-6"></div>
                </div>
              ) : (
                <div className="whitespace-pre-wrap leading-relaxed text-slate-700">
                  {/* Simple markdown rendering (replace # with h tags conceptually for this demo) */}
                  {activeLesson.content?.split('\n').map((line, i) => {
                    if (line.startsWith('# ')) return <h1 key={i} className="text-3xl font-bold mt-8 mb-4 text-slate-900">{line.substring(2)}</h1>;
                    if (line.startsWith('## ')) return <h2 key={i} className="text-2xl font-bold mt-6 mb-3 text-slate-800">{line.substring(3)}</h2>;
                    if (line.startsWith('### ')) return <h3 key={i} className="text-xl font-bold mt-5 mb-2 text-slate-800">{line.substring(4)}</h3>;
                    if (line.startsWith('- ')) return <li key={i} className="ml-4 text-slate-700">{line.substring(2)}</li>;
                    return <p key={i} className="mb-4">{line}</p>;
                  })}
                </div>
              )}
            </div>

          </div>
        ) : (
          <div className="flex flex-col items-center justify-center h-full text-slate-400">
            <BookIcon />
            <p className="mt-4">Select a lesson to begin editing</p>
          </div>
        )}
      </main>
    </div>
  );
};

export default CourseBuilder;

