{
  "name": "ScormGenAI",
  "description": "Uma ferramenta de autoria de cursos com IA. Gera esboços de cursos, conteúdo de lições e usa o Gemini Nano para criar ilustrações educacionais instantaneamente.",
  "requestFramePermissions": []
}

import { GoogleGenAI, Type } from "@google/genai";
import { Course, Module, Lesson } from "../types";

const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean up JSON string if the model adds backticks
const cleanJson = (text: string) => {
  return text.replace(/^```json\s*/, "").replace(/\s*```$/, "");
};

/**
 * Generates a course outline based on a topic.
 * Uses gemini-3-flash-preview for fast structural reasoning.
 */
export const generateCourseOutline = async (topic: string, language: string = 'Português do Brasil'): Promise<Course> => {
  const ai = getAiClient();

  const prompt = `Crie um esboço detalhado de curso para um treinamento SCORM sobre: "${topic}". 
  A saída deve estar estritamente em ${language}.
  O curso deve ter 2-3 módulos, e cada módulo deve ter 2-3 lições.
  Forneça uma breve descrição do curso.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          modules: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                lessons: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      title: { type: Type.STRING },
                      imagePrompt: { type: Type.STRING, description: "Uma descrição visual detalhada para gerar uma imagem educacional que ajude o aluno a entender o conceito desta lição." }
                    },
                    required: ["title", "imagePrompt"]
                  }
                }
              },
              required: ["title", "lessons"]
            }
          }
        },
        required: ["title", "description", "modules"]
      }
    }
  });

  const rawText = response.text || "{}";
  const data = JSON.parse(cleanJson(rawText));

  // Transform into internal types with IDs
  const course: Course = {
    id: crypto.randomUUID(),
    title: data.title,
    description: data.description,
    language: language,
    modules: data.modules.map((m: any) => ({
      id: crypto.randomUUID(),
      title: m.title,
      lessons: m.lessons.map((l: any) => ({
        id: crypto.randomUUID(),
        title: l.title,
        imagePrompt: l.imagePrompt,
        content: "", // Content generated later on demand
      }))
    }))
  };

  return course;
};

/**
 * Generates the text content for a specific lesson.
 */
export const generateLessonContent = async (lessonTitle: string, courseTitle: string, language: string): Promise<string> => {
  const ai = getAiClient();
  const prompt = `Escreva uma lição educacional abrangente em formato Markdown para a lição "${lessonTitle}" que faz parte do curso "${courseTitle}". 
  Idioma: ${language}.
  Estrutura:
  - Introdução
  - Conceitos Chave (lista com marcadores)
  - Explicação Detalhada
  - Resumo/Conclusão
  Mantenha o tom engajador e adequado para e-learning (SCORM). Não inclua imagens no markdown, apenas texto.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
  });

  return response.text || "Falha ao gerar o conteúdo.";
};

/**
 * Generates an educational image using the Nano Banana model (gemini-2.5-flash-image).
 */
export const generateLessonImage = async (imagePrompt: string): Promise<string | undefined> => {
  const ai = getAiClient();

  // Refine prompt for educational style in Portuguese/English mix for better understanding or pure descriptions
  // Using translated style keywords to match the user request for a Portuguese app context, 
  // but Gemini handles English style descriptors well too.
  const refinedPrompt = `Ilustração educacional, design plano (flat), estilo vetorial limpo, fundo branco, fácil de entender. ${imagePrompt}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: {
        parts: [{ text: refinedPrompt }]
      }
    });

    // Extract image from parts
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Image generation failed:", error);
    return undefined;
  }

  return undefined;
};

