import { GoogleGenAI, Type } from "@google/genai";
import { Course, Module, Lesson, FileContext } from "../types";

const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean up JSON string if the model adds backticks
const cleanJson = (text: string) => {
  return text.replace(/^```json\s*/, "").replace(/\s*```$/, "");
};

// Helper to extract raw base64 from data URI if present
const getBase64Data = (dataUri: string) => {
  return dataUri.includes(',') ? dataUri.split(',')[1] : dataUri;
};

/**
 * Generates a course outline based on a detailed description, files, and audience.
 * Uses gemini-3-flash-preview for fast structural reasoning with large context.
 */
export const generateCourseOutline = async (
  detailedContent: string, 
  targetAudience: string,
  files: FileContext[],
  language: string = 'Português do Brasil'
): Promise<Course> => {
  const ai = getAiClient();

  const textPrompt = `Atue como um designer instrucional especialista. Crie um esboço detalhado de curso para um treinamento SCORM.

  CONTEÚDO/TÓPICO:
  ${detailedContent}

  PÚBLICO-ALVO:
  ${targetAudience}

  INSTRUÇÕES:
  1. Analise os arquivos fornecidos (se houver) para entender o contexto e o material de referência.
  2. A saída deve estar estritamente em ${language}.
  3. O curso deve ter 2-4 módulos lógicos.
  4. Cada módulo deve ter 2-4 lições.
  5. Para cada lição, crie um 'imagePrompt' muito detalhado que descreva uma ilustração visual simples para ajudar o aluno a entender o conceito específico daquela lição.
  6. Forneça uma breve descrição do curso.`;

  // Construct parts: Text prompt + Files
  const parts: any[] = [{ text: textPrompt }];

  files.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          modules: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                lessons: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      title: { type: Type.STRING },
                      imagePrompt: { type: Type.STRING, description: "Descrição visual para gerar imagem educacional." }
                    },
                    required: ["title", "imagePrompt"]
                  }
                }
              },
              required: ["title", "lessons"]
            }
          }
        },
        required: ["title", "description", "modules"]
      }
    }
  });

  const rawText = response.text || "{}";
  const data = JSON.parse(cleanJson(rawText));

  // Transform into internal types with IDs
  const course: Course = {
    id: crypto.randomUUID(),
    title: data.title,
    description: data.description,
    language: language,
    targetAudience: targetAudience,
    contextFiles: files, // Store files in course for lesson generation
    modules: data.modules.map((m: any) => ({
      id: crypto.randomUUID(),
      title: m.title,
      lessons: m.lessons.map((l: any) => ({
        id: crypto.randomUUID(),
        title: l.title,
        imagePrompt: l.imagePrompt,
        content: "", 
      }))
    }))
  };

  return course;
};

/**
 * Generates the text content for a specific lesson, using the course files as context.
 */
export const generateLessonContent = async (
  lessonTitle: string, 
  course: Course
): Promise<string> => {
  const ai = getAiClient();

  const textPrompt = `Você é um conteudista educacional. Escreva o conteúdo para a seguinte lição:

  CURSO: ${course.title}
  LIÇÃO: ${lessonTitle}
  PÚBLICO-ALVO: ${course.targetAudience}
  IDIOMA: ${course.language}

  INSTRUÇÕES:
  1. Use os arquivos anexados como fonte da verdade para o conteúdo técnico (se houver).
  2. Formato: Markdown.
  3. Estrutura sugerida:
     - Introdução Engajadora
     - Objetivos da Lição
     - Desenvolvimento do Conteúdo (Use subtítulos, listas e negrito)
     - Cenário Prático ou Exemplo (adaptado ao público-alvo)
     - Resumo/Pontos Chave
  4. Mantenha um tom adequado ao público-alvo.
  5. Não inclua placeholders de imagem, apenas o texto explicativo.`;

  const parts: any[] = [{ text: textPrompt }];

  // Re-attach files so the model can reference specific details for this lesson
  course.contextFiles.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
  });

  return response.text || "Falha ao gerar o conteúdo.";
};

/**
 * Generates an educational image using the Nano Banana model (gemini-2.5-flash-image).
 */
export const generateLessonImage = async (imagePrompt: string): Promise<string | undefined> => {
  const ai = getAiClient();

  const refinedPrompt = `Ilustração educacional corporativa, estilo flat design moderno, vetorial, fundo limpo, cores harmoniosas. O objetivo é explicar: ${imagePrompt}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: {
        parts: [{ text: refinedPrompt }]
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Image generation failed:", error);
    return undefined;
  }

  return undefined;
};

