  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" x2="12" y1="3" y2="15"/></svg>
);

const FileIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M14.5 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7.5L14.5 2z"/><polyline points="14 2 14 8 20 8"/></svg>
);

const TrashIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg>
);

interface CourseBuilderProps {}

const CourseBuilder: React.FC<CourseBuilderProps> = () => {
  const [detailedContent, setDetailedContent] = useState('');
  const [targetAudience, setTargetAudience] = useState('');
  const [files, setFiles] = useState<FileContext[]>([]);

  const [loading, setLoading] = useState(false);
  const [course, setCourse] = useState<Course | null>(null);
  const [activeLessonId, setActiveLessonId] = useState<string | null>(null);
  const [generatingImageId, setGeneratingImageId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: FileContext[] = [];
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const base64 = await convertFileToBase64(file);
        newFiles.push({
          name: file.name,
          mimeType: file.type,
          data: base64
        });
      }
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const convertFileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const handleCreateCourse = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!detailedContent.trim()) return;

    setLoading(true);
    try {
      const generatedCourse = await GeminiService.generateCourseOutline(
        detailedContent, 
        targetAudience, 
        files
      );
      setCourse(generatedCourse);

      // Select first lesson by default
      if (generatedCourse.modules.length > 0 && generatedCourse.modules[0].lessons.length > 0) {
        setActiveLessonId(generatedCourse.modules[0].lessons[0].id);
        // Trigger content generation for the first lesson immediately
        fetchLessonContent(generatedCourse.modules[0].lessons[0], generatedCourse);
      }
    } catch (error) {
      console.error("Error creating course:", error);
      alert("Falha ao criar a estrutura do curso. Por favor, tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  const fetchLessonContent = async (lesson: Lesson, currentCourse: Course) => {
    // If content exists, don't regenerate
    if (lesson.content) return;

    updateLesson(lesson.id, { isLoading: true });

    try {
      const content = await GeminiService.generateLessonContent(lesson.title, currentCourse);
      updateLesson(lesson.id, { content, isLoading: false });
    } catch (error) {
      console.error("Error fetching content:", error);
      updateLesson(lesson.id, { isLoading: false, content: "Erro ao carregar conteúdo." });
    }
  };

  const generateImageForLesson = async (lesson: Lesson) => {
    if (!lesson.imagePrompt) return;
    setGeneratingImageId(lesson.id);

    try {
      const imageUrl = await GeminiService.generateLessonImage(lesson.imagePrompt);
      if (imageUrl) {
        updateLesson(lesson.id, { imageUrl });
      }
    } catch (error) {
      console.error("Error generating image:", error);
    } finally {
      setGeneratingImageId(null);
    }
  };

  const updateLesson = (lessonId: string, updates: Partial<Lesson>) => {
    setCourse(prev => {
      if (!prev) return null;
      const newModules = prev.modules.map(mod => ({
        ...mod,
        lessons: mod.lessons.map(les => 
          les.id === lessonId ? { ...les, ...updates } : les
        )
      }));
      return { ...prev, modules: newModules };
    });
  };

  const handleLessonSelect = (lesson: Lesson) => {
    setActiveLessonId(lesson.id);
    if (!lesson.content && course) {
      fetchLessonContent(lesson, course);
    }
  };

  const getActiveLesson = () => {
    if (!course) return null;
    for (const mod of course.modules) {
      for (const les of mod.lessons) {
        if (les.id === activeLessonId) return les;
      }
    }
    return null;
  };

  const activeLesson = getActiveLesson();

  // Simulated SCORM Export
  const handleExport = () => {
    if (!course || !activeLesson) return;

    // Create a simple HTML blob representing a "SCORM Package"
    const htmlContent = `
    <!DOCTYPE html>
    <html lang="pt-BR">
    <head><title>${activeLesson.title}</title></head>
    <body style="font-family: sans-serif; max-width: 800px; margin: 0 auto; padding: 20px;">
      <h1>${activeLesson.title}</h1>
      ${activeLesson.imageUrl ? `<img src="${activeLesson.imageUrl}" style="max-width: 100%; border-radius: 8px; margin-bottom: 20px;">` : ''}
      <div>${activeLesson.content?.replace(/\n/g, '<br>')}</div>
    </body>
    </html>
    `;

    const blob = new Blob([htmlContent], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `scorm_package_${activeLesson.title.replace(/\s+/g, '_')}.html`;
    a.click();
  };

  if (!course) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-gradient-to-br from-indigo-500 to-purple-600 p-4">
        <div className="bg-white rounded-2xl shadow-2xl p-8 max-w-2xl w-full">
          <div className="flex items-center justify-center mb-6">
            <div className="bg-indigo-100 p-3 rounded-full">
              <SparklesIcon />
            </div>
          </div>
          <h1 className="text-3xl font-bold text-center text-slate-800 mb-2">ScormGenAI</h1>
          <p className="text-center text-slate-500 mb-8">
            Configure seu curso para que a IA gere uma estrutura personalizada.
          </p>

          <form onSubmit={handleCreateCourse} className="space-y-6">
            {/* Topic / Detailed Content */}
            <div>
              <label htmlFor="content" className="block text-sm font-semibold text-slate-700 mb-2">
                Conteúdo Detalhado (O que você deseja ensinar?)
              </label>
              <textarea
                id="content"
                value={detailedContent}
                onChange={(e) => setDetailedContent(e.target.value)}
                placeholder="Ex: Quero um curso sobre segurança cibernética focado em phishing, senhas fortes e engenharia social. Deve abordar protocolos de e-mail..."
                className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-colors h-32 resize-none"
                disabled={loading}
              />
            </div>

            {/* Target Audience */}
            <div>
              <label htmlFor="audience" className="block text-sm font-semibold text-slate-700 mb-2">
                Público-Alvo
              </label>
              <input
                type="text"
                id="audience"
                value={targetAudience}
                onChange={(e) => setTargetAudience(e.target.value)}
                placeholder="Ex: Novos funcionários, 20-30 anos, conhecimento técnico básico."
                className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-colors"
                disabled={loading}
              />
            </div>

            {/* File Upload */}
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">
                Arquivos de Contexto (PDF, Imagens, Texto)
              </label>
              <div 
                className={`border-2 border-dashed rounded-lg p-6 text-center transition-colors cursor-pointer ${
                  loading ? 'bg-slate-50 border-slate-200' : 'border-indigo-200 hover:border-indigo-400 hover:bg-indigo-50'
                }`}
                onClick={() => !loading && fileInputRef.current?.click()}
              >
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  className="hidden" 
                  multiple 
                  accept="application/pdf,image/*,text/plain"
                  onChange={handleFileChange}
                />
                <div className="flex flex-col items-center justify-center text-indigo-500 mb-2">
                  <UploadIcon />
                </div>
                <p className="text-sm text-slate-600 font-medium">Clique para importar arquivos</p>
                <p className="text-xs text-slate-400 mt-1">Ajude a IA a entender melhor o seu material</p>
              </div>

              {/* File List */}
              {files.length > 0 && (
                <div className="mt-4 space-y-2">
                  {files.map((file, idx) => (
                    <div key={idx} className="flex items-center justify-between bg-slate-50 px-3 py-2 rounded border border-slate-200 text-sm">
                      <div className="flex items-center truncate">
                        <span className="text-slate-400 mr-2"><FileIcon /></span>
                        <span className="truncate max-w-[200px] text-slate-700" title={file.name}>{file.name}</span>
                      </div>
                      <button 
                        type="button" 
                        onClick={() => removeFile(idx)}
                        className="text-red-400 hover:text-red-600 p-1"
                        disabled={loading}
                      >
                        <TrashIcon />
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <button
              type="submit"
              disabled={loading || !detailedContent.trim()}
              className={`w-full flex items-center justify-center py-3 px-4 rounded-lg text-white font-medium transition-all ${
                loading || !detailedContent.trim()
                  ? 'bg-indigo-300 cursor-not-allowed' 
                  : 'bg-indigo-600 hover:bg-indigo-700 shadow-lg hover:shadow-indigo-500/30'
              }`}
            >
              {loading ? (
                <>
                  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Analisando & Gerando...
                </>
              ) : (
                <>
                  <SparklesIcon />
                  <span className="ml-2">Gerar Curso com IA</span>
                </>
              )}
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar - Course Navigation */}
      <aside className="w-80 bg-white border-r border-slate-200 flex flex-col h-full z-10">
        <div className="p-5 border-b border-slate-100">
          <h2 className="font-bold text-lg text-slate-800 line-clamp-1">{course.title}</h2>
          <p className="text-xs text-slate-500 mt-1 line-clamp-2">{course.description}</p>
          {course.contextFiles.length > 0 && (
             <div className="mt-3 flex items-center text-xs text-indigo-600 bg-indigo-50 px-2 py-1 rounded w-fit">
                <FileIcon />
                <span className="ml-1">{course.contextFiles.length} arquivos de contexto</span>
             </div>
          )}
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-6">
          {course.modules.map((module, mIdx) => (
            <div key={module.id}>
              <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 pl-2">
                Módulo {mIdx + 1}: {module.title}
              </h3>
              <div className="space-y-1">
                {module.lessons.map((lesson) => (
                  <button
                    key={lesson.id}
                    onClick={() => handleLessonSelect(lesson)}
                    className={`w-full text-left px-3 py-2 rounded-md text-sm transition-colors flex items-center group ${
                      activeLessonId === lesson.id
                        ? 'bg-indigo-50 text-indigo-700 font-medium'
                        : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900'
                    }`}
                  >
                    <BookIcon />
                    <span className="ml-3 truncate">{lesson.title}</span>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>

        <div className="p-4 border-t border-slate-100 bg-slate-50">
          <button 
            onClick={handleExport}
            className="w-full flex items-center justify-center py-2 px-4 border border-slate-300 rounded-md text-sm font-medium text-slate-700 bg-white hover:bg-slate-50 transition-colors"
          >
            <DownloadIcon />
            <span className="ml-2">Exportar Pacote SCORM</span>
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto bg-white/50 relative">
        {activeLesson ? (
          <div className="max-w-4xl mx-auto px-8 py-12">

            {/* Header */}
            <div className="mb-8 border-b border-slate-100 pb-8">
              <h1 className="text-4xl font-extrabold text-slate-900 mb-4 tracking-tight">
                {activeLesson.title}
              </h1>
              <div className="flex items-center gap-2">
                 <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                   Gerado por IA
                 </span>
                 <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                   {course.language}
                 </span>
                 {course.targetAudience && (
                    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-purple-100 text-purple-800 max-w-[200px] truncate">
                      {course.targetAudience}
                    </span>
                 )}
              </div>
            </div>

            {/* AI Image Section */}
            <div className="mb-10 bg-slate-50 rounded-xl border border-slate-100 p-1 overflow-hidden">
               {activeLesson.imageUrl ? (
                 <div className="relative group">
                   <img 
                    src={activeLesson.imageUrl} 
                    alt="Conteúdo Educacional Gerado por IA" 
                    className="w-full h-auto rounded-lg object-cover max-h-[400px]"
                   />
                   <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors rounded-lg pointer-events-none" />
                 </div>
               ) : (
                 <div className="h-64 flex flex-col items-center justify-center bg-slate-100 rounded-lg border-2 border-dashed border-slate-300 p-6 text-center">
                   {generatingImageId === activeLesson.id ? (
                     <div className="flex flex-col items-center animate-pulse">
                       <div className="w-12 h-12 bg-indigo-200 rounded-full mb-3" />
                       <p className="text-slate-500 font-medium">Gerando visualização Nano Banana...</p>
                       <p className="text-xs text-slate-400 mt-1">Usando gemini-2.5-flash-image</p>
                     </div>
                   ) : (
                     <>
                        <div className="bg-white p-3 rounded-full shadow-sm mb-3">
                          <ImageIcon />
                        </div>
                        <h3 className="text-sm font-medium text-slate-900">Nenhuma Visualização Ainda</h3>
                        <p className="text-xs text-slate-500 mt-1 mb-4 max-w-sm">
                          Melhore esta lição com uma imagem gerada por IA personalizada para explicar os conceitos.
                        </p>
                        <button
                          onClick={() => generateImageForLesson(activeLesson)}
                          className="px-4 py-2 bg-indigo-600 text-white text-sm rounded-md shadow-sm hover:bg-indigo-700 transition-all flex items-center"
                        >
                          <SparklesIcon />
                          <span className="ml-2">Gerar Imagem (Nano Banana)</span>
                        </button>
                     </>
                   )}
                 </div>
               )}
            </div>

            {/* Lesson Content */}
            <div className="prose prose-slate lg:prose-lg max-w-none">
              {activeLesson.isLoading ? (
                <div className="space-y-4 animate-pulse">
                  <div className="h-4 bg-slate-200 rounded w-3/4"></div>
                  <div className="h-4 bg-slate-200 rounded w-full"></div>
                  <div className="h-4 bg-slate-200 rounded w-5/6"></div>
                  <div className="h-32 bg-slate-200 rounded w-full mt-6"></div>
                </div>
              ) : (
                <div className="whitespace-pre-wrap leading-relaxed text-slate-700">
                  {/* Simple markdown rendering (replace # with h tags conceptually for this demo) */}
                  {activeLesson.content?.split('\n').map((line, i) => {
                    if (line.startsWith('# ')) return <h1 key={i} className="text-3xl font-bold mt-8 mb-4 text-slate-900">{line.substring(2)}</h1>;
                    if (line.startsWith('## ')) return <h2 key={i} className="text-2xl font-bold mt-6 mb-3 text-slate-800">{line.substring(3)}</h2>;
                    if (line.startsWith('### ')) return <h3 key={i} className="text-xl font-bold mt-5 mb-2 text-slate-800">{line.substring(4)}</h3>;
                    if (line.startsWith('- ')) return <li key={i} className="ml-4 text-slate-700">{line.substring(2)}</li>;
                    return <p key={i} className="mb-4">{line}</p>;
                  })}
                </div>
              )}
            </div>

          </div>
        ) : (
          <div className="flex flex-col items-center justify-center h-full text-slate-400">
            <BookIcon />
            <p className="mt-4">Selecione uma lição para começar</p>
          </div>
        )}
      </main>
    </div>
  );
};

export default CourseBuilder;

import { GoogleGenAI, Type } from "@google/genai";
import { Course, Module, Lesson, FileContext } from "../types";

const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean up JSON string if the model adds backticks
const cleanJson = (text: string) => {
  return text.replace(/^```json\s*/, "").replace(/\s*```$/, "");
};

// Helper to extract raw base64 from data URI if present
const getBase64Data = (dataUri: string) => {
  return dataUri.includes(',') ? dataUri.split(',')[1] : dataUri;
};

/**
 * Generates a course outline based on a detailed description, files, and audience.
 */
export const generateCourseOutline = async (
  detailedContent: string, 
  targetAudience: string,
  files: FileContext[],
  language: string = 'Português do Brasil'
): Promise<Course> => {
  const ai = getAiClient();

  const textPrompt = `Atue como um Arquiteto de Soluções e Designer Instrucional Sênior. Crie um esboço detalhado de curso técnico SCORM.

  CONTEÚDO/TÓPICO:
  ${detailedContent}

  PÚBLICO-ALVO:
  ${targetAudience}

  INSTRUÇÕES:
  1. Analise os arquivos fornecidos (se houver) para extrair detalhes técnicos precisos.
  2. A saída deve estar estritamente em ${language}.
  3. Estrutura: 2-3 Módulos. Cada módulo com 2-3 Lições.
  4. O conteúdo deve ser altamente técnico, focado em "como fazer" e arquitetura.
  5. Para cada lição, crie um 'imagePrompt' para um diagrama técnico ou arquitetural (flat design) que explique o conceito.
  6. Forneça uma breve descrição do curso.`;

  const parts: any[] = [{ text: textPrompt }];

  files.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          modules: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                lessons: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      title: { type: Type.STRING },
                      imagePrompt: { type: Type.STRING, description: "Descrição técnica para diagrama ou ilustração." }
                    },
                    required: ["title", "imagePrompt"]
                  }
                }
              },
              required: ["title", "lessons"]
            }
          }
        },
        required: ["title", "description", "modules"]
      }
    }
  });

  const rawText = response.text || "{}";
  const data = JSON.parse(cleanJson(rawText));

  const course: Course = {
    id: crypto.randomUUID(),
    title: data.title,
    description: data.description,
    language: language,
    targetAudience: targetAudience,
    contextFiles: files,
    modules: data.modules.map((m: any) => ({
      id: crypto.randomUUID(),
      title: m.title,
      lessons: m.lessons.map((l: any) => ({
        id: crypto.randomUUID(),
        title: l.title,
        imagePrompt: l.imagePrompt,
        content: "", 
      }))
    }))
  };

  return course;
};

/**
 * Generates the HTML content for a specific lesson matching the Template style.
 */
export const generateLessonContent = async (
  lessonTitle: string, 
  course: Course
): Promise<string> => {
  const ai = getAiClient();

  const textPrompt = `Você é um Engenheiro de Software Sênior e Criador de Conteúdo Técnico.
  Escreva o conteúdo para a lição: "${lessonTitle}" do curso "${course.title}".

  CONTEXTO TÉCNICO (Público: ${course.targetAudience}):
  Use os arquivos anexados como referência técnica absoluta.

  DIRETRIZES DE FORMATO (CRÍTICO):
  1. Retorne APENAS código HTML válido (sem tag html/body, apenas o conteúdo da div).
  2. Use classes Tailwind CSS para estilização.
  3. NÃO use Markdown. Use HTML.
  4. Estilo Visual: Clean, corporativo (azul/slate), use ícones FontAwesome (<i class="fas fa-..."></i>).

  ESTRUTURA OBRIGATÓRIA DO HTML:
  - Container principal: <div class="p-8 lg:p-12 h-full custom-scroll overflow-y-auto">
  - Título: <h2 class="text-3xl font-bold text-slate-900 mb-6">...</h2>
  - Use <p class="text-slate-600 mb-4 leading-relaxed"> para parágrafos.
  - Para listas, use cards ou bullet points estilizados.
  - INCLUA UM FLUXOGRAMA/DIAGRAMA: Use a sintaxe Mermaid dentro de uma div assim: 
    <div class="mermaid bg-slate-50 p-4 rounded-xl border border-slate-200 mb-8 text-center">
       graph TD; A[Node] --> B[Node];
    </div>
  - INCLUA EXEMPLOS TÉCNICOS/CÓDIGO: Use blocos assim:
    <div class="code-block rounded-xl p-6 shadow-inner mb-6 text-sm">
       <pre><code>...código...</code></pre>
    </div>

  O conteúdo deve ser prático, ensinando "como fazer" ou explicando a arquitetura profundamente.`;

  const parts: any[] = [{ text: textPrompt }];

  course.contextFiles.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
  });

  // Clean markdown code blocks if the model adds them by mistake
  let cleanHtml = response.text || "";
  cleanHtml = cleanHtml.replace(/^```html\s*/, "").replace(/^```\s*/, "").replace(/\s*```$/, "");

  return cleanHtml;
};

/**
 * Generates an educational image using the Nano Banana model (gemini-2.5-flash-image).
 */
export const generateLessonImage = async (imagePrompt: string): Promise<string | undefined> => {
  const ai = getAiClient();

  const refinedPrompt = `Tech illustration, flat design, vector style, white background, clean lines, corporate blue and slate colors. Diagrammatic representation of: ${imagePrompt}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: {
        parts: [{ text: refinedPrompt }]
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Image generation failed:", error);
    return undefined;
  }

  return undefined;
};

