  // Load Mermaid Script
  useEffect(() => {
    const script = document.createElement('script');
    script.src = "https://cdn.jsdelivr.net/npm/mermaid/dist/mermaid.min.js";
    script.onload = () => {
      // @ts-ignore
      window.mermaid.initialize({ startOnLoad: true, theme: 'neutral' });
    };
    document.head.appendChild(script);
  }, []);

  // --- File Handlers ---
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: FileContext[] = [];
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const base64 = await convertFileToBase64(file);
        newFiles.push({
          name: file.name,
          mimeType: file.type,
          data: base64
        });
      }
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const convertFileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  // --- Course Generation Handlers ---
  const handleCreateCourse = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!detailedContent.trim()) return;

    setLoading(true);
    try {
      const generatedCourse = await GeminiService.generateCourseOutline(
        detailedContent, 
        targetAudience, 
        files
      );
      setCourse(generatedCourse);

      if (generatedCourse.modules.length > 0 && generatedCourse.modules[0].lessons.length > 0) {
        setActiveLessonId(generatedCourse.modules[0].lessons[0].id);
        fetchLessonContent(generatedCourse.modules[0].lessons[0], generatedCourse);
      }
    } catch (error) {
      console.error("Error creating course:", error);
      alert("Falha ao criar a estrutura do curso. Por favor, tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  const fetchLessonContent = async (lesson: Lesson, currentCourse: Course) => {
    if (lesson.content) return;
    updateLesson(lesson.id, { isLoading: true });
    try {
      const content = await GeminiService.generateLessonContent(lesson.title, currentCourse);
      updateLesson(lesson.id, { content, isLoading: false });
    } catch (error) {
      updateLesson(lesson.id, { isLoading: false, content: "<div class='p-8 text-red-500'>Erro ao gerar conteúdo.</div>" });
