import { GoogleGenAI, Type } from "@google/genai";
import { Course, Module, Lesson, FileContext } from "../types";

const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean up JSON string if the model adds backticks
const cleanJson = (text: string) => {
  return text.replace(/^```json\s*/, "").replace(/\s*```$/, "");
};

// Helper to extract raw base64 from data URI if present
const getBase64Data = (dataUri: string) => {
  return dataUri.includes(',') ? dataUri.split(',')[1] : dataUri;
};

/**
 * Generates a course outline based on a detailed description, files, and audience.
 */
export const generateCourseOutline = async (
  detailedContent: string, 
  targetAudience: string,
  files: FileContext[],
  language: string = 'Português do Brasil'
): Promise<Course> => {
  const ai = getAiClient();

  const textPrompt = `Atue como um Arquiteto de Soluções e Designer Instrucional Sênior. Crie um esboço detalhado de curso técnico SCORM.

  CONTEÚDO/TÓPICO:
  ${detailedContent}

  PÚBLICO-ALVO:
  ${targetAudience}

  INSTRUÇÕES:
  1. Analise os arquivos fornecidos (se houver) para extrair detalhes técnicos precisos.
  2. A saída deve estar estritamente em ${language}.
  3. Estrutura: 2-3 Módulos. Cada módulo com 2-3 Lições.
  4. O conteúdo deve ser altamente técnico, focado em "como fazer" e arquitetura.
  5. Para cada lição, crie um 'imagePrompt' para um diagrama técnico ou arquitetural (flat design) que explique o conceito.
  6. Forneça uma breve descrição do curso.`;

  const parts: any[] = [{ text: textPrompt }];

  files.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          modules: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                lessons: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      title: { type: Type.STRING },
                      imagePrompt: { type: Type.STRING, description: "Descrição técnica para diagrama ou ilustração." }
                    },
                    required: ["title", "imagePrompt"]
                  }
                }
              },
              required: ["title", "lessons"]
            }
          }
        },
        required: ["title", "description", "modules"]
      }
    }
  });

  const rawText = response.text || "{}";
  const data = JSON.parse(cleanJson(rawText));

  const course: Course = {
    id: crypto.randomUUID(),
    title: data.title,
    description: data.description,
    language: language,
    targetAudience: targetAudience,
    contextFiles: files,
    modules: data.modules.map((m: any) => ({
      id: crypto.randomUUID(),
      title: m.title,
      lessons: m.lessons.map((l: any) => ({
        id: crypto.randomUUID(),
        title: l.title,
        imagePrompt: l.imagePrompt,
        content: "", 
      }))
    }))
  };

  return course;
};

/**
 * Generates the HTML content for a specific lesson matching the Template style.
 */
export const generateLessonContent = async (
  lessonTitle: string, 
  course: Course
): Promise<string> => {
  const ai = getAiClient();

  const textPrompt = `Você é um Engenheiro de Software Sênior e Especialista no assunto.
  Escreva o conteúdo COMPLETO e DETALHADO para a lição: "${lessonTitle}" do curso "${course.title}".

  CONTEXTO TÉCNICO (Público: ${course.targetAudience}):
  Use os arquivos anexados como referência técnica absoluta.

  DIRETRIZES DE QUALIDADE (CRÍTICO):
  1. O conteúdo NÃO PODE ser um resumo. Deve ser um material de estudo COMPLETO, EXAUSTIVO e PROFUNDO sobre o tópico.
  2. Gere conteúdo preciso e factual. Se citar fatos específicos, garanta a veracidade.
  3. Ao raciocinar, pense passo a passo para construir o conhecimento de forma lógica.
  4. Se houver especulação, informe claramente: "Isto é especulativo". Se não souber algo com 100% de certeza, informe.
  5. Cite fontes ou referências oficiais quando aplicável (Ex: Documentação oficial, RFCs, Papers).
  6. Explique o "Porquê" e o "Como" de cada conceito técnico. Traga exemplos do mundo real.

  DIRETRIZES DE FORMATO (HTML):
  1. Retorne APENAS código HTML válido (apenas o conteúdo da div, sem tag html/body).
  2. Use classes Tailwind CSS para estilização. Estilo Visual: Clean, corporativo.
  3. Use ícones FontAwesome (<i class="fas fa-..."></i>) para enriquecer visualmente.

  ESTRUTURA OBRIGATÓRIA DO HTML:
  - Container principal: <div class="p-8 lg:p-12 h-full custom-scroll overflow-y-auto">
  - Título: <h2 class="text-3xl font-bold text-slate-900 mb-6">...</h2>
  - Subtítulos: <h3 class="text-xl font-bold text-slate-800 mt-8 mb-4">...</h3>
  - Texto: <p class="text-slate-600 mb-4 leading-relaxed text-lg">...
  - Destaques: Use caixas de alerta ou info (bg-blue-50 border-blue-200) para pontos cruciais.
  - FLUXOGRAMA: Se necessário para explicar um processo, use a sintaxe Mermaid: 
    <div class="mermaid bg-slate-50 p-4 rounded-xl border border-slate-200 mb-8 text-center">graph TD; ...</div>
  - CÓDIGO: Use blocos para exemplos práticos:
    <div class="code-block rounded-xl p-6 shadow-inner mb-6 text-sm"><pre><code>...</code></pre></div>

  Certifique-se de que o aluno saia desta lição com conhecimento aprofundado e aplicável.`;

  const parts: any[] = [{ text: textPrompt }];

  course.contextFiles.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  // Using gemini-3-flash-preview with thinking config for deeper reasoning on structure
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      thinkingConfig: { thinkingBudget: 1024 } // Enable thinking to plan the comprehensive lesson
    }
  });

  // Clean markdown code blocks if the model adds them by mistake
  let cleanHtml = response.text || "";
  cleanHtml = cleanHtml.replace(/^```html\s*/, "").replace(/^```\s*/, "").replace(/\s*```$/, "");

  return cleanHtml;
};

/**
 * Generates an educational image using the Nano Banana model (gemini-2.5-flash-image).
 */
export const generateLessonImage = async (imagePrompt: string): Promise<string | undefined> => {
  const ai = getAiClient();

  const refinedPrompt = `Tech illustration, flat design, vector style, white background, clean lines, corporate blue and slate colors. Diagrammatic representation of: ${imagePrompt}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: {
        parts: [{ text: refinedPrompt }]
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Image generation failed:", error);
    return undefined;
  }

  return undefined;
};

