interface CourseBuilderProps {}

const CourseBuilder: React.FC<CourseBuilderProps> = () => {
  // Input State
  const [detailedContent, setDetailedContent] = useState('');
  const [targetAudience, setTargetAudience] = useState('');
  const [files, setFiles] = useState<FileContext[]>([]);
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // App State
  const [course, setCourse] = useState<Course | null>(null);
  const [activeLessonId, setActiveLessonId] = useState<string | null>(null);
  const [generatingImageId, setGeneratingImageId] = useState<string | null>(null);

  // Editor State
  const [isEditing, setIsEditing] = useState(false);
  const [mediaInput, setMediaInput] = useState('');
  const [mediaType, setMediaType] = useState<'video' | 'drive' | null>(null);

  // Mermaid Initialization
  useEffect(() => {
    if (activeLessonId && !isEditing) {
      // @ts-ignore
      if (window.mermaid) {
        // @ts-ignore
        window.mermaid.init(undefined, document.querySelectorAll('.mermaid'));
      }
    }
  }, [activeLessonId, isEditing, course]);

  // Load Mermaid Script
  useEffect(() => {
    const script = document.createElement('script');
    script.src = "https://cdn.jsdelivr.net/npm/mermaid/dist/mermaid.min.js";
    script.onload = () => {
      // @ts-ignore
      window.mermaid.initialize({ startOnLoad: true, theme: 'neutral' });
    };
    document.head.appendChild(script);
  }, []);

  // --- File Handlers ---
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: FileContext[] = [];
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const base64 = await convertFileToBase64(file);
        newFiles.push({
          name: file.name,
          mimeType: file.type,
          data: base64
        });
      }
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const convertFileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  // --- Course Generation Handlers ---
  const handleCreateCourse = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!detailedContent.trim()) return;

    setLoading(true);
    try {
      const generatedCourse = await GeminiService.generateCourseOutline(
        detailedContent, 
        targetAudience, 
        files
      );
      setCourse(generatedCourse);

      if (generatedCourse.modules.length > 0 && generatedCourse.modules[0].lessons.length > 0) {
        setActiveLessonId(generatedCourse.modules[0].lessons[0].id);
        fetchLessonContent(generatedCourse.modules[0].lessons[0], generatedCourse);
      }
    } catch (error) {
      console.error("Error creating course:", error);
      alert("Falha ao criar a estrutura do curso. Por favor, tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  const fetchLessonContent = async (lesson: Lesson, currentCourse: Course) => {
    if (lesson.content) return;
    updateLesson(lesson.id, { isLoading: true });
    try {
      const content = await GeminiService.generateLessonContent(lesson.title, currentCourse);
      updateLesson(lesson.id, { content, isLoading: false });
    } catch (error) {
      updateLesson(lesson.id, { isLoading: false, content: "<div class='p-8 text-red-500'>Erro ao gerar conteúdo.</div>" });
    }
  };

  const generateImageForLesson = async (lesson: Lesson) => {
    if (!lesson.imagePrompt) return;
    setGeneratingImageId(lesson.id);
    try {
      const imageUrl = await GeminiService.generateLessonImage(lesson.imagePrompt);
      if (imageUrl) {
        updateLesson(lesson.id, { imageUrl });
      }
    } finally {
      setGeneratingImageId(null);
    }
  };

  const updateLesson = (lessonId: string, updates: Partial<Lesson>) => {
    setCourse(prev => {
      if (!prev) return null;
      const newModules = prev.modules.map(mod => ({
        ...mod,
        lessons: mod.lessons.map(les => 
          les.id === lessonId ? { ...les, ...updates } : les
        )
      }));
      return { ...prev, modules: newModules };
    });
  };

  // --- Editor Handlers ---
  const handleContentChange = (newContent: string) => {
    if (activeLessonId) {
      updateLesson(activeLessonId, { content: newContent });
    }
  };

  // Improved ID extraction for robustness
  const getYoutubeId = (url: string) => {
    const regExp = /^.*((youtu.be\/)|(v\/)|(\/u\/\w\/)|(embed\/)|(watch\?))\??v?=?([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[7].length === 11) ? match[7] : null;
  }

  const insertMedia = () => {
    if (!mediaInput || !activeLessonId) return;
    const lesson = getActiveLesson();
    if (!lesson) return;

    let snippet = '';

    if (mediaType === 'video') {
      const videoId = getYoutubeId(mediaInput);

      if (videoId) {
        // Updated iframe with necessary permissions for Error 153 fix
        snippet = `
          <div class="my-8 bg-white p-2 rounded-xl border border-slate-200 shadow-sm">
             <div class="aspect-video-wrapper bg-slate-100 relative pb-[56.25%] h-0 overflow-hidden rounded-lg">
                <iframe 
                  src="https://www.youtube.com/embed/${videoId}?rel=0&modestbranding=1" 
                  class="absolute top-0 left-0 w-full h-full" 
                  frameborder="0" 
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" 
                  referrerpolicy="strict-origin-when-cross-origin" 
                  allowfullscreen>
                </iframe>
             </div>
          </div>
        `;
      } else {
        alert("Link do YouTube inválido.");
        return;
      }
    } else if (mediaType === 'drive') {
      snippet = `
        <div class="my-6 p-4 bg-blue-50 border border-blue-200 rounded-xl flex items-center gap-4 hover:bg-blue-100 transition">
           <div class="w-10 h-10 bg-blue-600 rounded-full flex items-center justify-center text-white"><i class="fas fa-cloud-download-alt"></i></div>
           <div class="flex-1">
             <h4 class="font-bold text-slate-800">Material Complementar</h4>
             <p class="text-sm text-slate-600">Acesse o arquivo no Google Drive.</p>
           </div>
           <a href="${mediaInput}" target="_blank" class="px-4 py-2 bg-white text-blue-600 font-bold rounded-lg shadow-sm hover:shadow-md transition">Acessar</a>
        </div>
      `;
    }

    if (snippet) {
      updateLesson(activeLessonId, { content: (lesson.content || '') + snippet });
    }

    setMediaInput('');
    setMediaType(null);
  };

  // --- Export Logic ---
  const handleExport = () => {
    if (!course) return;

    // Flatten structure for the template
    let flatIndex = 0;
    const courseData = [];

    // Intro Slide (Auto-generated from description)
    courseData.push({
      id: flatIndex++,
      title: "Introdução do Curso",
      type: "content",
      content: `
         <div class="flex flex-col md:flex-row h-full">
            <div class="md:w-1/2 p-8 lg:p-12 flex flex-col justify-center bg-slate-50 border-r border-slate-100">
                  <span class="text-blue-600 font-bold tracking-wider text-sm mb-2 uppercase">Visão Geral</span>
                  <h2 class="text-4xl lg:text-5xl font-bold text-slate-900 mb-6 leading-tight">${course.title}</h2>
                  <p class="text-lg text-slate-600 leading-relaxed mb-8">${course.description}</p>
            </div>
            <div class="md:w-1/2 relative overflow-hidden bg-slate-900 flex items-center justify-center">
                <div class="text-white text-center p-10">
                   <i class="fas fa-rocket text-6xl mb-4 text-blue-400"></i>
                   <h3 class="text-2xl font-bold">Comece sua jornada</h3>
                </div>
            </div>
         </div>
      `
    });

    // Modules & Lessons
    course.modules.forEach(mod => {
      // Section Divider (Optional, can be a slide)

      mod.lessons.forEach(lesson => {
        let finalContent = lesson.content || "";
        // Inject Image if exists and not already in HTML (rough check)
        if (lesson.imageUrl && !finalContent.includes('<img')) {
             finalContent = `
               <div class="p-8 lg:p-12 h-full custom-scroll overflow-y-auto">
                 <div class="max-w-4xl mx-auto">
                   <div class="mb-8 rounded-xl overflow-hidden shadow-md border border-slate-200">
                      <img src="${lesson.imageUrl}" alt="${lesson.title}" class="w-full object-cover max-h-[300px]" />
                   </div>
                   ${finalContent.replace('<div class="p-8 lg:p-12 h-full custom-scroll overflow-y-auto">', '').replace(/<\/div>$/, '')} 
                 </div>
               </div>
             `;
             // Note: The replace above is a hack to strip the outer container if AI added it, to prevent double scrolling.
             // A cleaner way is to strip the wrapper in generated content if we wrap it here.
        }

        courseData.push({
          id: flatIndex++,
          title: lesson.title,
          type: "content",
          content: finalContent
        });
      });
    });

    // Conclusion Slide
    courseData.push({
      id: flatIndex++,
      title: "Conclusão",
      type: "final",
      content: `
        <div class="h-full flex flex-col items-center justify-center text-center p-8 bg-gradient-to-b from-white to-blue-50">
            <div class="mb-6 relative">
                <div class="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center text-5xl text-white shadow-xl animate-[bounce_2s_infinite]">
                    <i class="fas fa-trophy"></i>
                </div>
            </div>
            <h2 class="text-4xl font-bold text-slate-900 mb-4">Curso Concluído!</h2>
            <p class="text-lg text-slate-600 max-w-md mb-8">
                Parabéns! Você completou o treinamento sobre ${course.title}.
            </p>
            <button onclick="exitCourse()" class="px-8 py-4 magalu-gradient text-white rounded-xl font-bold shadow-lg shadow-blue-500/30 hover:scale-105 transition transform">
                Finalizar e Sair
            </button>
        </div>
      `
    });

    const template = getScormTemplate(JSON.stringify(courseData), course.title);
    const blob = new Blob([template], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `SCORM_${course.title.replace(/\s+/g, '_')}.html`;
    a.click();
  };

  // --- Helper: Scorm Template String ---
  // This contains the exact HTML structure requested by the user
  const getScormTemplate = (dataJson: string, title: string) => `
<!DOCTYPE html>
<html lang="pt-BR">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${title}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css" rel="stylesheet">
    <script src="https://cdn.jsdelivr.net/npm/canvas-confetti@1.6.0/dist/confetti.browser.min.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/mermaid/dist/mermaid.min.js"></script>
    <style>
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=Fira+Code:wght@400;500&display=swap');
        body { font-family: 'Inter', sans-serif; background-color: #f8fafc; overflow: hidden; user-select: none; }
        .magalu-gradient { background: linear-gradient(135deg, #0086FF 0%, #0050e6 100%); }
        .magalu-text-gradient { background: linear-gradient(135deg, #0086FF 0%, #0050e6 100%); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
        .fade-enter { animation: fadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .custom-scroll::-webkit-scrollbar { width: 6px; }
        .custom-scroll::-webkit-scrollbar-track { background: transparent; }
        .custom-scroll::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 10px; }
        .custom-scroll::-webkit-scrollbar-thumb:hover { background: #94a3b8; }
        .hover-card { transition: all 0.3s ease; border: 1px solid #e2e8f0; }
        .hover-card:hover { transform: translateY(-4px); box-shadow: 0 12px 24px -10px rgba(0, 134, 255, 0.15); border-color: #bfdbfe; }
        .aspect-video-wrapper { position: relative; padding-bottom: 56.25%; height: 0; overflow: hidden; border-radius: 0.75rem; box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1); }
        .aspect-video-wrapper iframe { position: absolute; top: 0; left: 0; width: 100%; height: 100%; }
        .code-block { font-family: 'Fira Code', monospace; background: #1e293b; color: #e2e8f0; }
    </style>
</head>
<body class="h-screen flex flex-col text-slate-800">
    <header class="bg-white/80 backdrop-blur-md border-b border-slate-200 z-20 flex-none h-16 px-6 flex items-center justify-between shadow-sm">
        <div class="flex items-center gap-4">
            <img src="https://media.licdn.com/dms/image/v2/D4D0BAQGlkyJOKvz6WQ/company-logo_200_200/company-logo_200_200/0/1718300941618/extremedigitalsolutions_logo?e=2147483647&v=beta&t=fUKXMHsSI8xi-6Xa5mVIMCWMPQ7wlQUPQZud_XASSls" class="w-10 h-10 rounded-lg shadow-lg object-contain bg-white" alt="Logo">
            <div>
                <h1 class="text-base font-bold text-slate-800 leading-tight">${title}</h1>
                <p class="text-xs text-slate-500 font-medium tracking-wide uppercase">Curso Interativo</p>
            </div>
        </div>
        <div class="flex items-center gap-6">
            <div class="hidden md:flex flex-col items-end w-48">
                <div class="flex justify-between w-full text-xs font-semibold text-slate-500 mb-1"><span>Progresso</span><span id="progress-text">0%</span></div>
                <div class="w-full h-2 bg-slate-100 rounded-full overflow-hidden"><div id="progress-bar" class="h-full magalu-gradient transition-all duration-500 ease-out" style="width: 0%"></div></div>
            </div>
            <button onclick="exitCourse()" class="text-slate-400 hover:text-red-500 transition-colors p-2 rounded-full hover:bg-red-50"><i class="fas fa-power-off"></i></button>
        </div>
    </header>
    <main class="flex-grow relative overflow-hidden bg-slate-50 flex items-center justify-center p-4 sm:p-6 lg:p-10">
        <div id="content-area" class="w-full max-w-6xl bg-white rounded-2xl shadow-xl border border-slate-100 h-full overflow-hidden relative flex flex-col fade-enter"></div>
    </main>
    <footer class="bg-white border-t border-slate-200 h-20 flex-none flex items-center justify-between px-6 sm:px-10 z-10">
        <button id="btn-prev" onclick="prevSlide()" class="group flex items-center gap-2 px-5 py-2.5 rounded-xl text-slate-600 font-semibold hover:bg-slate-100 disabled:opacity-40 transition-all"><i class="fas fa-arrow-left group-hover:-translate-x-1 transition-transform"></i><span>Anterior</span></button>
        <div class="bg-slate-100 px-4 py-1.5 rounded-full text-sm font-semibold text-slate-500 tracking-wider"><span id="slide-indicator">1 / 1</span></div>
        <button id="btn-next" onclick="nextSlide()" class="group flex items-center gap-2 px-6 py-2.5 rounded-xl magalu-gradient text-white font-semibold hover:shadow-lg disabled:opacity-50 transition-all"><span>Próximo</span><i class="fas fa-arrow-right group-hover:translate-x-1 transition-transform"></i></button>
    </footer>
    <script>
        const courseData = ${dataJson};
        // SCORM API SIMULATION / IMPLEMENTATION
        const scorm = {
            api: null, version: null, startTime: new Date(),
            init: function() {
                try {
                    let parentWin = window.parent;
                    if (parentWin && parentWin.API_1484_11) { this.api = parentWin.API_1484_11; this.version = "2004"; this.api.Initialize(""); } 
                    else if (parentWin && parentWin.API) { this.api = parentWin.API; this.version = "1.2"; this.api.LMSInitialize(""); }
                    else { console.log("Standalone Mode"); }
                    if(this.api) this.setStatus("incomplete");
                } catch (e) { console.warn(e); }
            },
            setStatus: function(s) { if(!this.api) return; this.version==="2004" ? this.api.SetValue("cmi.completion_status", s==='passed'?'completed':s) : this.api.LMSSetValue("cmi.core.lesson_status", s); this.commit(); },
            setBookmark: function(l) { if(!this.api) return; this.version==="2004" ? this.api.SetValue("cmi.location", l) : this.api.LMSSetValue("cmi.core.lesson_location", l); this.commit(); },
            getBookmark: function() { if(!this.api) return null; return this.version==="2004" ? this.api.GetValue("cmi.location") : this.api.LMSGetValue("cmi.core.lesson_location"); },
            commit: function() { if(this.api) this.version==="2004" ? this.api.Commit("") : this.api.LMSCommit(""); },
            finish: function() { if(this.api) this.version==="2004" ? this.api.Terminate("") : this.api.LMSFinish(""); }
        };

        let currentSlide = 0;
        function initApp() {
            scorm.init();
            mermaid.initialize({ startOnLoad: true, theme: 'neutral' });
            const bookmark = scorm.getBookmark();
            if (bookmark && parseInt(bookmark) > 0) currentSlide = parseInt(bookmark);
            renderSlide(currentSlide);
        }
        function renderSlide(index) {
            currentSlide = index;
            const container = document.getElementById("content-area");
            const data = courseData[index];
            container.classList.remove("fade-enter");
            void container.offsetWidth; 
            container.classList.add("fade-enter");
            container.innerHTML = data.content;

            // Re-init mermaid
            setTimeout(() => { mermaid.init(undefined, document.querySelectorAll('.mermaid')); }, 100);

            updateControls(index, data.type);
            updateProgress();
            scorm.setBookmark(index);
        }
        function updateControls(index, type) {
            document.getElementById("slide-indicator").innerText = (index + 1) + " / " + courseData.length;
            document.getElementById("btn-prev").disabled = index === 0;
            const btnNext = document.getElementById("btn-next");
            if (type === "final") btnNext.style.display = "none";
            else { btnNext.style.display = "flex"; btnNext.disabled = index === courseData.length - 1; }
        }
        function updateProgress() {
            const p = ((currentSlide + 1) / courseData.length) * 100;
            document.getElementById("progress-bar").style.width = p + "%";
            document.getElementById("progress-text").innerText = Math.round(p) + "%";
        }
        function nextSlide() { if (currentSlide < courseData.length - 1) renderSlide(currentSlide + 1); }
        function prevSlide() { if (currentSlide > 0) renderSlide(currentSlide - 1); }
        function exitCourse() { scorm.finish(); window.close(); }
        window.onload = initApp;
    </script>
</body>
</html>`;

  // --- Render Navigation ---
  const handleLessonSelect = (lesson: Lesson) => {
    setActiveLessonId(lesson.id);
    if (!lesson.content && course) {
      fetchLessonContent(lesson, course);
    }
  };

  const getActiveLesson = () => {
    if (!course) return null;
    for (const mod of course.modules) {
      for (const les of mod.lessons) {
        if (les.id === activeLessonId) return les;
      }
    }
    return null;
  };

  const activeLesson = getActiveLesson();

  // --- View: Initial Form ---
  if (!course) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-gradient-to-br from-indigo-500 to-purple-600 p-4">
        <div className="bg-white rounded-2xl shadow-2xl p-8 max-w-2xl w-full">
          <div className="flex items-center justify-center mb-6">
            <div className="bg-indigo-100 p-3 rounded-full"><SparklesIcon /></div>
          </div>
          <h1 className="text-3xl font-bold text-center text-slate-800 mb-2">ScormGenAI</h1>
          <p className="text-center text-slate-500 mb-8">Criador de Cursos Técnicos com IA e Template Magalu Cloud.</p>

          <form onSubmit={handleCreateCourse} className="space-y-6">
            <div>
              <label htmlFor="content" className="block text-sm font-semibold text-slate-700 mb-2">Conteúdo Detalhado</label>
              <textarea id="content" value={detailedContent} onChange={(e) => setDetailedContent(e.target.value)} placeholder="Descreva o conteúdo técnico, módulos e objetivos..." className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 transition-colors h-32 resize-none" disabled={loading} />
            </div>
            <div>
              <label htmlFor="audience" className="block text-sm font-semibold text-slate-700 mb-2">Público-Alvo</label>
              <input type="text" id="audience" value={targetAudience} onChange={(e) => setTargetAudience(e.target.value)} placeholder="Ex: Desenvolvedores Sênior, DevOps..." className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 transition-colors" disabled={loading} />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">Arquivos de Contexto</label>
              <div className={`border-2 border-dashed rounded-lg p-6 text-center transition-colors cursor-pointer ${loading ? 'bg-slate-50 border-slate-200' : 'border-indigo-200 hover:border-indigo-400 hover:bg-indigo-50'}`} onClick={() => !loading && fileInputRef.current?.click()}>
                <input type="file" ref={fileInputRef} className="hidden" multiple accept="application/pdf,image/*,text/plain" onChange={handleFileChange} />
                <div className="flex flex-col items-center justify-center text-indigo-500 mb-2"><UploadIcon /></div>
                <p className="text-sm text-slate-600 font-medium">Importar arquivos</p>
              </div>
              {files.length > 0 && (
                <div className="mt-4 space-y-2">{files.map((file, idx) => (<div key={idx} className="flex justify-between bg-slate-50 px-3 py-2 rounded border border-slate-200 text-sm"><span className="truncate">{file.name}</span><button type="button" onClick={() => removeFile(idx)} className="text-red-400"><TrashIcon /></button></div>))}</div>
              )}
            </div>
            <button type="submit" disabled={loading || !detailedContent.trim()} className={`w-full flex items-center justify-center py-3 px-4 rounded-lg text-white font-medium transition-all ${loading ? 'bg-indigo-300' : 'bg-indigo-600 hover:bg-indigo-700'}`}>{loading ? 'Gerando Estrutura...' : 'Gerar Curso'}</button>
          </form>
        </div>
      </div>
    );
  }

  // --- View: Main App ---
  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-80 bg-white border-r border-slate-200 flex flex-col h-full z-10 shadow-sm">
        <div className="p-5 border-b border-slate-100">
          <h2 className="font-bold text-lg text-slate-800 truncate">{course.title}</h2>
          <p className="text-xs text-slate-500 mt-1 line-clamp-2">{course.description}</p>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-6">
          {course.modules.map((module, mIdx) => (
            <div key={module.id}>
              <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 pl-2">Módulo {mIdx + 1}: {module.title}</h3>
              <div className="space-y-1">
                {module.lessons.map((lesson) => (
                  <button key={lesson.id} onClick={() => handleLessonSelect(lesson)} className={`w-full text-left px-3 py-2 rounded-md text-sm transition-colors flex items-center ${activeLessonId === lesson.id ? 'bg-blue-50 text-blue-700 font-medium' : 'text-slate-600 hover:bg-slate-50'}`}><BookIcon /><span className="ml-3 truncate">{lesson.title}</span></button>
                ))}
              </div>
            </div>
          ))}
        </div>
        <div className="p-4 border-t border-slate-100 bg-slate-50">
          <button onClick={handleExport} className="w-full flex items-center justify-center py-2 px-4 border border-slate-300 rounded-md text-sm font-medium text-slate-700 bg-white hover:bg-slate-50"><DownloadIcon /><span className="ml-2">Exportar SCORM</span></button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto bg-slate-100 relative p-8 flex flex-col items-center">
        {activeLesson ? (
          <div className="w-full max-w-6xl flex flex-col h-full">
            {/* Toolbar */}
            <div className="flex justify-between items-center mb-6 bg-white p-4 rounded-xl shadow-sm border border-slate-200">
              <div>
                <h1 className="text-xl font-bold text-slate-800">{activeLesson.title}</h1>
                <span className="text-xs text-slate-500">
                  {activeLesson.isLoading ? 'Gerando conteúdo...' : 'Conteúdo pronto'}
                </span>
              </div>
              <div className="flex gap-3">
                 {/* Insert Media Tools (Only visible in edit mode or always? Lets do always for quick add) */}
                 {isEditing && (
                   <div className="flex items-center gap-2 mr-4 border-r border-slate-200 pr-4">
                      <div className="relative flex items-center">
                        <input 
                          type="text" 
                          placeholder={mediaType === 'video' ? 'Link Youtube...' : 'Link Drive...'} 
                          className={`text-sm border border-slate-300 rounded-l-md px-3 py-1.5 w-48 transition-all ${mediaType ? 'opacity-100' : 'opacity-0 w-0 px-0 border-0'}`}
                          value={mediaInput}
                          onChange={(e) => setMediaInput(e.target.value)}
                        />
                        <button 
                          onClick={() => { if(mediaType === 'video') insertMedia(); else setMediaType('video'); }} 
                          className={`p-2 rounded-md ${mediaType === 'video' ? 'bg-red-100 text-red-600 rounded-l-none' : 'bg-slate-100 hover:bg-red-50 hover:text-red-600'}`}
                          title="Inserir Youtube"
                        >
                          <VideoIcon />
                        </button>
                        <button 
                          onClick={() => { if(mediaType === 'drive') insertMedia(); else setMediaType('drive'); }} 
                          className={`p-2 rounded-md ml-1 ${mediaType === 'drive' ? 'bg-blue-100 text-blue-600 rounded-l-none' : 'bg-slate-100 hover:bg-blue-50 hover:text-blue-600'}`}
                          title="Inserir Drive"
                        >
                          <DriveIcon />
                        </button>
                      </div>
                   </div>
                 )}

                 <button onClick={() => setIsEditing(!isEditing)} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors ${isEditing ? 'bg-blue-600 text-white' : 'bg-white border border-slate-300 text-slate-700 hover:bg-slate-50'}`}>
                    {isEditing ? <><EyeIcon /><span>Visualizar</span></> : <><EditIcon /><span>Editar Código</span></>}
                 </button>
              </div>
            </div>

            {/* Editor / Preview Area */}
            <div className="flex-1 bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden relative min-h-[500px]">
               {activeLesson.isLoading ? (
                  <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/80 backdrop-blur-sm z-50">
                    <div className="w-10 h-10 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin mb-4"/>
                    <p className="text-indigo-600 font-medium animate-pulse">A IA está escrevendo o conteúdo técnico...</p>
                  </div>
               ) : null}

               {isEditing ? (
                 <div className="h-full flex flex-col">
                    <div className="bg-slate-800 text-slate-300 px-4 py-2 text-xs font-mono flex justify-between">
                      <span>HTML Source Editor</span>
                      <span>Use classes Tailwind</span>
                    </div>
                    <textarea 
                      className="flex-1 w-full p-6 font-mono text-sm text-slate-800 focus:outline-none resize-none bg-slate-50"
                      value={activeLesson.content || ''}
                      onChange={(e) => handleContentChange(e.target.value)}
                      spellCheck={false}
                    />
                 </div>
               ) : (
                 <div className="h-full w-full">
                    {/* SCORM PREVIEW MOCKUP - Trying to match the exported style roughly within the editor */}
                    <div className="h-full overflow-y-auto">
                        <div dangerouslySetInnerHTML={{ __html: activeLesson.content || '<div class="p-10 text-center text-slate-400">Conteúdo vazio.</div>' }} />

                        {/* Image Preview if exists */}
                        {activeLesson.imageUrl && !activeLesson.content?.includes('<img') && (
                          <div className="p-8 border-t border-slate-100">
                             <p className="text-xs text-slate-400 mb-2 uppercase font-bold">Imagem Gerada (Será inserida no topo ao exportar)</p>
                             <img src={activeLesson.imageUrl} alt="AI Generated" className="rounded-lg max-h-64 border border-slate-200" />
                          </div>
                        )}

                        {!activeLesson.imageUrl && !activeLesson.isLoading && (
                           <div className="p-6 flex justify-center border-t border-slate-50">
                              <button onClick={() => generateImageForLesson(activeLesson)} className="text-indigo-600 text-sm font-medium hover:underline flex items-center gap-2">
                                {generatingImageId === activeLesson.id ? 'Gerando...' : <><SparklesIcon /> Gerar Diagrama Visual (Nano Banana)</>}
                              </button>
                           </div>
                        )}
                    </div>
                 </div>
               )}
            </div>

          </div>
        ) : (
          <div className="flex flex-col items-center justify-center h-full text-slate-400">
            <BookIcon />
            <p className="mt-4">Selecione uma lição para começar</p>
          </div>
        )}
      </main>
    </div>
  );
};

export default CourseBuilder;

