  return cleanHtml;
};

/**
 * Generates an educational image using the Nano Banana model.
 */
export const generateLessonImage = async (imagePrompt: string): Promise<string | undefined> => {
  const ai = getAiClient();

  const refinedPrompt = `Tech illustration, flat design, vector style, white background, clean lines, corporate blue and slate colors. Diagrammatic representation of: ${imagePrompt}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: {
        parts: [{ text: refinedPrompt }]
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Image generation failed:", error);
    return undefined;
  }

  return undefined;
};

