interface CourseBuilderProps {}

const CourseBuilder: React.FC<CourseBuilderProps> = () => {
  // Input State
  const [detailedContent, setDetailedContent] = useState('');
  const [targetAudience, setTargetAudience] = useState('');
  const [docUrl, setDocUrl] = useState('');
  const [files, setFiles] = useState<FileContext[]>([]);
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // App State
  const [course, setCourse] = useState<Course | null>(null);
  const [activeLessonId, setActiveLessonId] = useState<string | null>(null);
  const [generatingImageId, setGeneratingImageId] = useState<string | null>(null);

  // Editor State
  const [isEditing, setIsEditing] = useState(false);
  const [mediaInput, setMediaInput] = useState('');
  const [mediaType, setMediaType] = useState<'video' | 'drive' | null>(null);

  // Mermaid Initialization
  useEffect(() => {
    if (activeLessonId && !isEditing) {
      // @ts-ignore
      if (window.mermaid) {
        // @ts-ignore
        window.mermaid.init(undefined, document.querySelectorAll('.mermaid'));
      }
    }
  }, [activeLessonId, isEditing, course]);

  // Load Mermaid Script
  useEffect(() => {
    const script = document.createElement('script');
    script.src = "https://cdn.jsdelivr.net/npm/mermaid/dist/mermaid.min.js";
    script.onload = () => {
      // @ts-ignore
      window.mermaid.initialize({ startOnLoad: true, theme: 'neutral' });
    };
    document.head.appendChild(script);
  }, []);

  // --- File Handlers ---
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: FileContext[] = [];
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const base64 = await convertFileToBase64(file);
        newFiles.push({
          name: file.name,
          mimeType: file.type,
          data: base64
        });
      }
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const convertFileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  // --- Course Generation Handlers ---
  const handleCreateCourse = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!detailedContent.trim()) return;

    setLoading(true);
    try {
      const generatedCourse = await GeminiService.generateCourseOutline(
        detailedContent, 
        targetAudience, 
        files,
        docUrl
      );
      setCourse(generatedCourse);

      if (generatedCourse.modules.length > 0 && generatedCourse.modules[0].lessons.length > 0) {
        setActiveLessonId(generatedCourse.modules[0].lessons[0].id);
        fetchLessonContent(generatedCourse.modules[0].lessons[0], generatedCourse);
      }
    } catch (error) {
      console.error("Error creating course:", error);
      alert("Falha ao criar a estrutura do curso. Por favor, tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  const fetchLessonContent = async (lesson: Lesson, currentCourse: Course) => {
    if (lesson.content) return;
    updateLesson(lesson.id, { isLoading: true });
    try {
      const content = await GeminiService.generateLessonContent(lesson.title, currentCourse);
      updateLesson(lesson.id, { content, isLoading: false });
    } catch (error) {
      updateLesson(lesson.id, { isLoading: false, content: "<div class='p-8 text-red-500'>Erro ao gerar conteúdo.</div>" });
    }
  };

  const generateImageForLesson = async (lesson: Lesson) => {
    if (!lesson.imagePrompt) return;
    setGeneratingImageId(lesson.id);
    try {
      const imageUrl = await GeminiService.generateLessonImage(lesson.imagePrompt);
      if (imageUrl) {
        updateLesson(lesson.id, { imageUrl });
      }
    } finally {
      setGeneratingImageId(null);
    }
  };

  const updateLesson = (lessonId: string, updates: Partial<Lesson>) => {
    setCourse(prev => {
      if (!prev) return null;
      const newModules = prev.modules.map(mod => ({
        ...mod,
        lessons: mod.lessons.map(les => 
          les.id === lessonId ? { ...les, ...updates } : les
        )
      }));
      return { ...prev, modules: newModules };
    });
  };

  // --- Editor Handlers ---
  const handleContentChange = (newContent: string) => {
    if (activeLessonId) {
      updateLesson(activeLessonId, { content: newContent });
    }
  };

  // Improved ID extraction for robustness
  const getYoutubeId = (url: string) => {
    const regExp = /^.*((youtu.be\/)|(v\/)|(\/u\/\w\/)|(embed\/)|(watch\?))\??v?=?([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[7].length === 11) ? match[7] : null;
  };

  const insertMedia = () => {
    if (!mediaInput || !activeLessonId) return;
    const lesson = getActiveLesson();
    if (!lesson) return;

    let snippet = '';

    if (mediaType === 'video') {
      const videoId = getYoutubeId(mediaInput);

      if (videoId) {
        // Add origin to help with permissions (Error 153) and a fallback link
        const origin = window.location.origin;
        snippet = `
          <div class="my-8 bg-white p-2 rounded-xl border border-slate-200 shadow-sm">
             <div class="aspect-video-wrapper bg-slate-100 relative pb-[56.25%] h-0 overflow-hidden rounded-lg">
                <iframe 
                  src="https://www.youtube.com/embed/${videoId}?rel=0&modestbranding=1&origin=${origin}" 
                  class="absolute top-0 left-0 w-full h-full" 
                  frameborder="0" 
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" 
                  referrerpolicy="strict-origin-when-cross-origin" 
                  allowfullscreen>
                </iframe>
             </div>
             <div class="mt-2 text-right">
                <a href="https://www.youtube.com/watch?v=${videoId}" target="_blank" rel="noopener noreferrer" class="text-xs text-blue-500 hover:underline"><i class="fas fa-external-link-alt"></i> Assistir no YouTube (caso o vídeo não carregue)</a>
             </div>
          </div>
        `;
      } else {
        alert("Link do YouTube inválido.");
        return;
      }
    } else if (mediaType === 'drive') {
      snippet = `
        <div class="my-6 p-4 bg-blue-50 border border-blue-200 rounded-xl flex items-center gap-4 hover:bg-blue-100 transition">
           <div class="w-10 h-10 bg-blue-600 rounded-full flex items-center justify-center text-white"><i class="fas fa-cloud-download-alt"></i></div>
           <div class="flex-1">
             <h4 class="font-bold text-slate-800">Material Complementar</h4>
             <p class="text-sm text-slate-600">Acesse o arquivo no Google Drive.</p>
           </div>
           <a href="${mediaInput}" target="_blank" class="px-4 py-2 bg-white text-blue-600 font-bold rounded-lg shadow-sm hover:shadow-md transition">Acessar</a>
        </div>
      `;
    }

    if (snippet) {
      updateLesson(activeLessonId, { content: (lesson.content || '') + snippet });
    }

    setMediaInput('');
    setMediaType(null);
  };

  // --- Export Logic ---
  const handleExport = () => {
    if (!course) return;

    // Flatten structure for the template
    let flatIndex = 0;
    const courseData = [];

    // Intro Slide
    courseData.push({
      id: flatIndex++,
      title: "Introdução do Curso",
      type: "content",
      content: `
         <div class="flex flex-col md:flex-row h-full">
            <div class="md:w-1/2 p-8 lg:p-12 flex flex-col justify-center bg-slate-50 border-r border-slate-100">
                  <span class="text-blue-600 font-bold tracking-wider text-sm mb-2 uppercase">Visão Geral</span>
                  <h2 class="text-4xl lg:text-5xl font-bold text-slate-900 mb-6 leading-tight">${course.title}</h2>
                  <p class="text-lg text-slate-600 leading-relaxed mb-8">${course.description}</p>
            </div>
            <div class="md:w-1/2 relative overflow-hidden bg-slate-900 flex items-center justify-center">
                <div class="text-white text-center p-10">
                   <i class="fas fa-rocket text-6xl mb-4 text-blue-400"></i>
                   <h3 class="text-2xl font-bold">Comece sua jornada</h3>
                </div>
            </div>
         </div>
      `
    });

    // Modules & Lessons
    course.modules.forEach(mod => {
      mod.lessons.forEach(lesson => {
        let finalContent = lesson.content || "";
        // Inject Image if exists
        if (lesson.imageUrl && !finalContent.includes('<img')) {
             finalContent = `
               <div class="p-8 lg:p-12 h-full custom-scroll overflow-y-auto">
                 <div class="max-w-4xl mx-auto">
                   <div class="mb-8 rounded-xl overflow-hidden shadow-md border border-slate-200">
                      <img src="${lesson.imageUrl}" alt="${lesson.title}" class="w-full object-cover max-h-[300px]" />
                   </div>
                   ${finalContent.replace('<div class="p-8 lg:p-12 h-full custom-scroll overflow-y-auto">', '').replace(/<\/div>$/, '')} 
                 </div>
               </div>
             `;
        }

        courseData.push({
          id: flatIndex++,
          title: lesson.title,
          type: "content",
          content: finalContent
        });
      });
    });

    // Conclusion Slide
    courseData.push({
      id: flatIndex++,
      title: "Conclusão",
      type: "final",
      content: `
        <div class="h-full flex flex-col items-center justify-center text-center p-8 bg-gradient-to-b from-white to-blue-50">
            <div class="mb-6 relative">
                <div class="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center text-5xl text-white shadow-xl animate-[bounce_2s_infinite]">
                    <i class="fas fa-trophy"></i>
                </div>
            </div>
            <h2 class="text-4xl font-bold text-slate-900 mb-4">Curso Concluído!</h2>
            <p class="text-lg text-slate-600 max-w-md mb-8">
                Parabéns! Você completou o treinamento sobre ${course.title}.
            </p>
            <button onclick="exitCourse()" class="px-8 py-4 magalu-gradient text-white rounded-xl font-bold shadow-lg shadow-blue-500/30 hover:scale-105 transition transform">
                Finalizar e Sair
            </button>
        </div>
      `
    });

    const template = getScormTemplate(JSON.stringify(courseData), course.title);
    const blob = new Blob([template], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `SCORM_${course.title.replace(/\s+/g, '_')}.html`;
    a.click();
  };

  // --- Helper: Scorm Template String ---
  const getScormTemplate = (dataJson: string, title: string) => `
<!DOCTYPE html>
<html lang="pt-BR">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${title}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css" rel="stylesheet">
    <script src="https://cdn.jsdelivr.net/npm/canvas-confetti@1.6.0/dist/confetti.browser.min.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/mermaid/dist/mermaid.min.js"></script>
    <style>
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=Fira+Code:wght@400;500&display=swap');
        body { font-family: 'Inter', sans-serif; background-color: #f8fafc; overflow: hidden; user-select: none; }
        .magalu-gradient { background: linear-gradient(135deg, #0086FF 0%, #0050e6 100%); }
        .magalu-text-gradient { background: linear-gradient(135deg, #0086FF 0%, #0050e6 100%); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
        .fade-enter { animation: fadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .custom-scroll::-webkit-scrollbar { width: 6px; }
        .custom-scroll::-webkit-scrollbar-track { background: transparent; }
        .custom-scroll::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 10px; }
        .custom-scroll::-webkit-scrollbar-thumb:hover { background: #94a3b8; }
        .hover-card { transition: all 0.3s ease; border: 1px solid #e2e8f0; }
        .hover-card:hover { transform: translateY(-4px); box-shadow: 0 12px 24px -10px rgba(0, 134, 255, 0.15); border-color: #bfdbfe; }
        .aspect-video-wrapper { position: relative; padding-bottom: 56.25%; height: 0; overflow: hidden; border-radius: 0.75rem; box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1); }
        .aspect-video-wrapper iframe { position: absolute; top: 0; left: 0; width: 100%; height: 100%; }
        .code-block { font-family: 'Fira Code', monospace; background: #1e293b; color: #e2e8f0; }
    </style>
</head>
<body class="h-screen flex flex-col text-slate-800">
    <header class="bg-white/80 backdrop-blur-md border-b border-slate-200 z-20 flex-none h-16 px-6 flex items-center justify-between shadow-sm">
        <div class="flex items-center gap-4">
            <img src="https://media.licdn.com/dms/image/v2/D4D0BAQGlkyJOKvz6WQ/company-logo_200_200/company-logo_200_200/0/1718300941618/extremedigitalsolutions_logo?e=2147483647&v=beta&t=fUKXMHsSI8xi-6Xa5mVIMCWMPQ7wlQUPQZud_XASSls" class="w-10 h-10 rounded-lg shadow-lg object-contain bg-white" alt="Logo">
            <div>
                <h1 class="text-base font-bold text-slate-800 leading-tight">${title}</h1>
                <p class="text-xs text-slate-500 font-medium tracking-wide uppercase">Curso Interativo</p>
            </div>
        </div>
        <div class="flex items-center gap-6">
            <div class="hidden md:flex flex-col items-end w-48">
                <div class="flex justify-between w-full text-xs font-semibold text-slate-500 mb-1"><span>Progresso</span><span id="progress-text">0%</span></div>
                <div class="w-full h-2 bg-slate-100 rounded-full overflow-hidden"><div id="progress-bar" class="h-full magalu-gradient transition-all duration-500 ease-out" style="width: 0%"></div></div>
            </div>
            <button onclick="exitCourse()" class="text-slate-400 hover:text-red-500 transition-colors p-2 rounded-full hover:bg-red-50"><i class="fas fa-power-off"></i></button>
        </div>
    </header>
    <main class="flex-grow relative overflow-hidden bg-slate-50 flex items-center justify-center p-4 sm:p-6 lg:p-10">
        <div id="content-area" class="w-full max-w-6xl bg-white rounded-2xl shadow-xl border border-slate-100 h-full overflow-hidden relative flex flex-col fade-enter"></div>
    </main>
    <footer class="bg-white border-t border-slate-200 h-20 flex-none flex items-center justify-between px-6 sm:px-10 z-10">
        <button id="btn-prev" onclick="prevSlide()" class="group flex items-center gap-2 px-5 py-2.5 rounded-xl text-slate-600 font-semibold hover:bg-slate-100 disabled:opacity-40 transition-all"><i class="fas fa-arrow-left group-hover:-translate-x-1 transition-transform"></i><span>Anterior</span></button>
        <div class="bg-slate-100 px-4 py-1.5 rounded-full text-sm font-semibold text-slate-500 tracking-wider"><span id="slide-indicator">1 / 1</span></div>
        <button id="btn-next" onclick="nextSlide()" class="group flex items-center gap-2 px-6 py-2.5 rounded-xl magalu-gradient text-white font-semibold hover:shadow-lg disabled:opacity-50 transition-all"><span>Próximo</span><i class="fas fa-arrow-right group-hover:translate-x-1 transition-transform"></i></button>
    </footer>
    <script>
        const courseData = ${dataJson};
        // SCORM API SIMULATION / IMPLEMENTATION
        const scorm = {
            api: null, version: null, startTime: new Date(),
            init: function() {
                try {
                    let parentWin = window.parent;
                    if (parentWin && parentWin.API_1484_11) { this.api = parentWin.API_1484_11; this.version = "2004"; this.api.Initialize(""); } 
                    else if (parentWin && parentWin.API) { this.api = parentWin.API; this.version = "1.2"; this.api.LMSInitialize(""); }
                    else { console.log("Standalone Mode"); }
                    if(this.api) this.setStatus("incomplete");
                } catch (e) { console.warn(e); }
            },
            setStatus: function(s) { if(!this.api) return; this.version==="2004" ? this.api.SetValue("cmi.completion_status", s==='passed'?'completed':s) : this.api.LMSSetValue("cmi.core.lesson_status", s); this.commit(); },
            setBookmark: function(l) { if(!this.api) return; this.version==="2004" ? this.api.SetValue("cmi.location", l) : this.api.LMSSetValue("cmi.core.lesson_location", l); this.commit(); },
            getBookmark: function() { if(!this.api) return null; return this.version==="2004" ? this.api.GetValue("cmi.location") : this.api.LMSGetValue("cmi.core.lesson_location"); },
            commit: function() { if(this.api) this.version==="2004" ? this.api.Commit("") : this.api.LMSCommit(""); },
            finish: function() { if(this.api) this.version==="2004" ? this.api.Terminate("") : this.api.LMSFinish(""); }
        };

        let currentSlide = 0;
        function initApp() {
            scorm.init();
            mermaid.initialize({ startOnLoad: true, theme: 'neutral' });
            const bookmark = scorm.getBookmark();
            if (bookmark && parseInt(bookmark) > 0) currentSlide = parseInt(bookmark);
            renderSlide(currentSlide);
        }
        function renderSlide(index) {
            currentSlide = index;
            const container = document.getElementById("content-area");
            const data = courseData[index];
            container.classList.remove("fade-enter");
            void container.offsetWidth; 
            container.classList.add("fade-enter");
            container.innerHTML = data.content;

            // Re-init mermaid
            setTimeout(() => { mermaid.init(undefined, document.querySelectorAll('.mermaid')); }, 100);

            updateControls(index, data.type);
            updateProgress();
            scorm.setBookmark(index);
        }
        function updateControls(index, type) {
            document.getElementById("slide-indicator").innerText = (index + 1) + " / " + courseData.length;
            document.getElementById("btn-prev").disabled = index === 0;
            const btnNext = document.getElementById("btn-next");
            if (type === "final") btnNext.style.display = "none";
            else { btnNext.style.display = "flex"; btnNext.disabled = index === courseData.length - 1; }
        }
        function updateProgress() {
            const p = ((currentSlide + 1) / courseData.length) * 100;
            document.getElementById("progress-bar").style.width = p + "%";
            document.getElementById("progress-text").innerText = Math.round(p) + "%";
        }
        function nextSlide() { if (currentSlide < courseData.length - 1) renderSlide(currentSlide + 1); }
        function prevSlide() { if (currentSlide > 0) renderSlide(currentSlide - 1); }
        function exitCourse() { scorm.finish(); window.close(); }
        window.onload = initApp;
    </script>
</body>
</html>`;

  // --- Render Navigation ---
  const handleLessonSelect = (lesson: Lesson) => {
    setActiveLessonId(lesson.id);
    if (!lesson.content && course) {
      fetchLessonContent(lesson, course);
    }
  };

  const getActiveLesson = () => {
    if (!course) return null;
    for (const mod of course.modules) {
      for (const les of mod.lessons) {
        if (les.id === activeLessonId) return les;
      }
    }
    return null;
  };

  const activeLesson = getActiveLesson();

  // --- View: Initial Form (Wizard Style) ---
  if (!course) {
    return (
      <div className="flex flex-col min-h-screen bg-slate-50 font-sans text-slate-900 selection:bg-blue-100 selection:text-blue-700">
         {/* Simple Navbar */}
         <div className="w-full bg-white border-b border-slate-200 py-4 px-8 flex justify-between items-center">
            <div className="flex items-center gap-2 text-indigo-600 font-bold text-xl tracking-tight">
               <SparklesIcon className="w-6 h-6" />
               <span>ScormGenAI</span>
            </div>
            <div className="text-sm text-slate-500">v1.0.3</div>
         </div>

         {/* Wizard Content */}
         <div className="flex-1 flex flex-col items-center justify-center p-6">
            <div className="w-full max-w-3xl bg-white rounded-2xl shadow-xl border border-slate-100 overflow-hidden">
               <div className="p-1 bg-gradient-to-r from-blue-500 via-indigo-500 to-purple-500"></div>
               <div className="p-8 md:p-12">
                  <div className="text-center mb-10">
                    <h1 className="text-3xl md:text-4xl font-bold text-slate-900 mb-4 tracking-tight">Crie seu curso com IA</h1>
                    <p className="text-lg text-slate-600 max-w-xl mx-auto">
                      Transforme seus documentos e ideias em um curso SCORM interativo e visualmente rico em segundos.
                    </p>
                  </div>

                  <form onSubmit={handleCreateCourse} className="space-y-8">
                     <div className="space-y-4">
                        <label htmlFor="content" className="block text-sm font-semibold text-slate-900 uppercase tracking-wider">O que você quer ensinar?</label>
                        <div className="relative">
                          <textarea 
                            id="content" 
                            value={detailedContent} 
                            onChange={(e) => setDetailedContent(e.target.value)} 
                            placeholder="Descreva o tópico, módulos desejados ou cole o conteúdo bruto aqui..." 
                            className="w-full p-4 rounded-xl bg-slate-50 border border-slate-200 focus:bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none resize-none h-40 text-lg"
                            disabled={loading}
                          />
                        </div>
                     </div>

                     <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-2">
                           <label htmlFor="audience" className="block text-sm font-semibold text-slate-900 uppercase tracking-wider">Para quem?</label>
                           <input 
                             type="text" 
                             id="audience" 
                             value={targetAudience} 
                             onChange={(e) => setTargetAudience(e.target.value)} 
                             placeholder="Ex: Iniciantes em Python..." 
                             className="w-full p-3 rounded-xl bg-slate-50 border border-slate-200 focus:bg-white focus:border-indigo-500 outline-none transition-all"
                             disabled={loading}
                           />
                        </div>
                        <div className="space-y-2">
                           <label htmlFor="docUrl" className="block text-sm font-semibold text-slate-900 uppercase tracking-wider flex items-center gap-2"><LinkIcon className="w-4 h-4 text-blue-500" /> Fonte Oficial</label>
                           <input 
                             type="url" 
                             id="docUrl" 
                             value={docUrl} 
                             onChange={(e) => setDocUrl(e.target.value)} 
                             placeholder="https://docs.exemplo.com..." 
                             className="w-full p-3 rounded-xl bg-slate-50 border border-slate-200 focus:bg-white focus:border-indigo-500 outline-none transition-all"
                             disabled={loading}
                           />
                        </div>
                     </div>

                     <div className="space-y-4">
                        <label className="block text-sm font-semibold text-slate-900 uppercase tracking-wider">Arquivos de Referência</label>
                        <div 
                          className={`border-2 border-dashed rounded-xl p-8 text-center transition-all cursor-pointer group ${loading ? 'bg-slate-50 border-slate-200 opacity-50' : 'border-slate-300 hover:border-indigo-400 hover:bg-indigo-50'}`} 
                          onClick={() => !loading && fileInputRef.current?.click()}
                        >
                          <input type="file" ref={fileInputRef} className="hidden" multiple accept="application/pdf,image/*,text/plain" onChange={handleFileChange} />
                          <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-3 group-hover:scale-110 transition-transform">
                             <UploadIcon className="w-6 h-6" />
                          </div>
                          <p className="text-slate-900 font-medium">Clique para fazer upload</p>
                          <p className="text-sm text-slate-500">PDF, TXT ou Imagens</p>
                        </div>
                        {files.length > 0 && (
                          <div className="flex flex-wrap gap-2">
                            {files.map((file, idx) => (
                              <div key={idx} className="flex items-center gap-2 bg-indigo-50 text-indigo-700 px-3 py-1.5 rounded-lg border border-indigo-100 text-sm font-medium">
                                <span className="truncate max-w-[150px]">{file.name}</span>
                                <button type="button" onClick={(e) => {e.stopPropagation(); removeFile(idx);}} className="text-indigo-400 hover:text-indigo-600"><TrashIcon /></button>
                              </div>
                            ))}
                          </div>
                        )}
                     </div>

                     <button 
                       type="submit" 
                       disabled={loading || !detailedContent.trim()} 
                       className={`w-full py-4 rounded-xl font-bold text-lg shadow-lg hover:shadow-xl hover:-translate-y-0.5 transition-all flex items-center justify-center gap-2 ${loading ? 'bg-slate-300 text-slate-500 cursor-not-allowed' : 'bg-gradient-to-r from-indigo-600 to-blue-600 text-white'}`}
                     >
                       {loading ? (
                         <><div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> <span>Analisando e Criando...</span></>
                       ) : (
                         <><SparklesIcon /> <span>Gerar Curso</span></>
                       )}
                     </button>
                  </form>
               </div>
            </div>

            {/* Footer / Credits */}
            <div className="mt-8 text-center text-slate-400 text-sm">
               Powered by Google Gemini Nano • Design inspired by Coursebox
            </div>
         </div>
      </div>
    );
  }

  // --- View: Workspace (Editor) ---
  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans">

      {/* 1. Sidebar Navigation */}
      <aside className="w-72 bg-white border-r border-slate-200 flex flex-col h-full z-20 shadow-sm flex-none">
        {/* Brand */}
        <div className="h-16 flex items-center px-6 border-b border-slate-100">
           <div className="flex items-center gap-2 font-bold text-slate-800">
              <div className="bg-indigo-600 p-1.5 rounded-lg text-white"><LayoutIcon className="w-4 h-4"/></div>
              <span className="tracking-tight">CourseBuilder</span>
           </div>
        </div>

        {/* Course Info */}
        <div className="p-6 pb-2">
           <h2 className="font-bold text-lg text-slate-900 leading-tight mb-1 line-clamp-2">{course.title}</h2>
           <p className="text-xs text-slate-500 font-medium uppercase tracking-wide">Estrutura do Curso</p>
        </div>

        {/* Navigation Tree */}
        <div className="flex-1 overflow-y-auto px-3 py-2 space-y-4 custom-scroll">
          {course.modules.map((module, mIdx) => (
            <div key={module.id} className="animate-fadeIn">
              <div className="px-3 py-2 text-xs font-bold text-slate-400 uppercase tracking-wider flex items-center gap-2">
                 <span>Módulo {mIdx + 1}</span>
              </div>
              <div className="space-y-0.5 mt-1">
                {module.lessons.map((lesson) => (
                  <button 
                    key={lesson.id} 
                    onClick={() => handleLessonSelect(lesson)} 
                    className={`w-full text-left px-3 py-2.5 rounded-lg text-sm transition-all flex items-center gap-3 group relative
                      ${activeLessonId === lesson.id 
                        ? 'bg-indigo-50 text-indigo-700 font-semibold shadow-sm' 
                        : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900'
                      }`}
                  >
                    {activeLessonId === lesson.id && <div className="absolute left-0 top-1/2 -translate-y-1/2 h-8 w-1 bg-indigo-600 rounded-r-full"></div>}
                    <span className={`flex-none ${activeLessonId === lesson.id ? 'text-indigo-600' : 'text-slate-400 group-hover:text-slate-600'}`}><BookIcon /></span>
                    <span className="truncate leading-snug">{lesson.title}</span>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>

        {/* Footer Actions */}
        <div className="p-4 border-t border-slate-100 bg-slate-50/50">
          <button onClick={handleExport} className="w-full flex items-center justify-center gap-2 py-2.5 bg-white border border-slate-200 rounded-xl text-sm font-semibold text-slate-700 shadow-sm hover:bg-slate-50 hover:border-slate-300 transition-all">
            <DownloadIcon />
            <span>Exportar SCORM</span>
          </button>
        </div>
      </aside>

      {/* 2. Main Canvas Area */}
      <main className="flex-1 flex flex-col relative h-full bg-slate-100/50">

        {/* Top Header / Toolbar */}
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 z-10 shadow-sm">
           {/* Breadcrumbs */}
           <div className="flex items-center gap-2 text-sm text-slate-500 overflow-hidden">
              <span className="hidden md:inline hover:text-slate-800 cursor-pointer transition-colors">Curso</span>
              <ChevronRight className="w-3 h-3 text-slate-300 hidden md:block" />
              <span className="truncate font-medium text-slate-900 max-w-[300px]">{activeLesson ? activeLesson.title : "Selecione uma lição"}</span>
              {activeLesson && activeLesson.isLoading && <span className="ml-2 text-xs bg-amber-100 text-amber-700 px-2 py-0.5 rounded-full animate-pulse">Gerando...</span>}
           </div>

           {/* Editor Actions */}
           <div className="flex items-center gap-2">
              {activeLesson && (
                <>
                  {/* Media Insert Group */}
                  <div className="flex bg-slate-100 rounded-lg p-1 mr-2 border border-slate-200">
                      <button 
                        onClick={() => setMediaType(mediaType === 'video' ? null : 'video')} 
                        className={`p-1.5 rounded-md transition-all ${mediaType === 'video' ? 'bg-white shadow text-red-600' : 'text-slate-500 hover:text-slate-700'}`}
                        title="Adicionar Vídeo"
                      >
                         <VideoIcon />
                      </button>
                      <button 
                        onClick={() => setMediaType(mediaType === 'drive' ? null : 'drive')} 
                        className={`p-1.5 rounded-md transition-all ${mediaType === 'drive' ? 'bg-white shadow text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}
                        title="Adicionar Drive"
                      >
                         <DriveIcon />
                      </button>
                  </div>

                  <button 
                    onClick={() => setIsEditing(!isEditing)} 
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all border ${isEditing ? 'bg-slate-800 border-slate-800 text-white' : 'bg-white border-slate-200 text-slate-700 hover:bg-slate-50'}`}
                  >
                     {isEditing ? <><EyeIcon /><span>Preview</span></> : <><EditIcon /><span>Código</span></>}
                  </button>
                </>
              )}
           </div>
        </header>

        {/* Media Input Popover (Floating) */}
        {mediaType && (
           <div className="absolute top-20 right-6 z-30 w-80 bg-white rounded-xl shadow-xl border border-slate-200 p-4 animate-in slide-in-from-top-2 fade-in">
              <h3 className="text-sm font-bold text-slate-800 mb-2">{mediaType === 'video' ? 'Inserir YouTube' : 'Inserir Google Drive'}</h3>
              <div className="flex gap-2">
                 <input 
                   autoFocus
                   type="text" 
                   value={mediaInput}
                   onChange={(e) => setMediaInput(e.target.value)}
                   placeholder="Cole a URL aqui..."
                   className="flex-1 text-sm border border-slate-300 rounded-lg px-3 py-2 outline-none focus:border-indigo-500 transition-colors"
                 />
                 <button onClick={insertMedia} className="bg-indigo-600 text-white px-3 py-2 rounded-lg text-sm font-bold hover:bg-indigo-700 transition-colors">OK</button>
              </div>
           </div>
        )}

        {/* Content Stage */}
        <div className="flex-1 overflow-y-auto p-4 md:p-8 flex justify-center">
          {activeLesson ? (
             <div className="w-full max-w-4xl animate-in fade-in zoom-in-95 duration-300">
               {/* Lesson Card */}
               <div className="bg-white min-h-[800px] rounded-xl shadow-sm border border-slate-200 overflow-hidden relative flex flex-col">

                  {/* AI Loading Overlay */}
                  {activeLesson.isLoading && (
                     <div className="absolute inset-0 z-50 bg-white/90 backdrop-blur-sm flex flex-col items-center justify-center">
                        <div className="w-12 h-12 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin mb-4 shadow-lg"></div>
                        <p className="text-indigo-900 font-semibold animate-pulse">Criando conteúdo da lição...</p>
                        <p className="text-sm text-indigo-500 mt-2">Consultando documentos e estruturando...</p>
                     </div>
                  )}

                  {isEditing ? (
                     <div className="flex-1 flex flex-col bg-slate-900">
                        <div className="flex-none bg-slate-800 px-4 py-2 text-xs text-slate-400 font-mono flex justify-between items-center">
                           <span>HTML SOURCE CODE</span>
                           <span className="bg-slate-700 px-2 py-0.5 rounded text-slate-300">Tailwind CSS Enabled</span>
                        </div>
                        <textarea 
                           className="flex-1 w-full p-6 font-mono text-sm text-slate-300 bg-slate-900 focus:outline-none resize-none leading-relaxed"
                           value={activeLesson.content || ''}
                           onChange={(e) => handleContentChange(e.target.value)}
                           spellCheck={false}
                        />
                     </div>
                  ) : (
                     <div className="flex-1 flex flex-col">
                        {/* Image Header or Generator */}
                        <div className="flex-none border-b border-slate-100 bg-slate-50/30 p-6 flex flex-col items-center justify-center min-h-[160px] relative group">
                           {activeLesson.imageUrl ? (
                              <div className="relative w-full">
                                 <img src={activeLesson.imageUrl} alt="Lesson Header" className="w-full h-64 object-cover rounded-lg shadow-sm" />
                                 <button 
                                    onClick={() => generateImageForLesson(activeLesson)}
                                    className="absolute bottom-4 right-4 bg-white/90 backdrop-blur text-slate-700 px-3 py-1.5 rounded-lg text-xs font-bold shadow hover:bg-white transition-all opacity-0 group-hover:opacity-100"
                                 >
                                    Regenerar Imagem
                                 </button>
                              </div>
                           ) : (
                              !activeLesson.isLoading && (
                                 <div className="text-center">
                                    <div className="bg-indigo-50 w-12 h-12 rounded-full flex items-center justify-center mx-auto mb-3 text-indigo-500">
                                       <ImageIcon className="w-6 h-6" />
                                    </div>
                                    <h3 className="text-sm font-semibold text-slate-700 mb-1">Ilustração Visual</h3>
                                    <p className="text-xs text-slate-500 mb-4 max-w-xs mx-auto">Adicione um diagrama ou ilustração gerada por IA para enriquecer o conteúdo.</p>
                                    <button 
                                       onClick={() => generateImageForLesson(activeLesson)}
                                       className="bg-white border border-indigo-200 text-indigo-600 px-4 py-2 rounded-lg text-sm font-semibold shadow-sm hover:bg-indigo-50 hover:border-indigo-300 transition-all flex items-center gap-2 mx-auto"
                                    >
                                       {generatingImageId === activeLesson.id ? <><div className="w-3 h-3 border-2 border-indigo-600 border-t-transparent rounded-full animate-spin"/> <span>Criando...</span></> : <><WandIcon /> <span>Gerar com Nano Banana</span></>}
                                    </button>
                                 </div>
                              )
                           )}
                        </div>

                        {/* HTML Content Render */}
                        <div className="flex-1 overflow-y-auto custom-scroll relative">
                           {activeLesson.content ? (
                              <div dangerouslySetInnerHTML={{ __html: activeLesson.content }} />
                           ) : (
                              <div className="h-full flex items-center justify-center text-slate-300 text-sm">
                                 Aguardando geração de conteúdo...
                              </div>
                           )}
                        </div>
                     </div>
                  )}
               </div>
             </div>
          ) : (
             <div className="flex flex-col items-center justify-center h-full text-slate-400 opacity-60">
               <div className="w-24 h-24 bg-slate-200 rounded-full flex items-center justify-center mb-6">
                  <LayoutIcon className="w-10 h-10 text-slate-400" />
               </div>
               <p className="text-lg font-medium text-slate-500">Selecione uma lição no menu lateral</p>
               <p className="text-sm">ou exporte o curso completo quando terminar</p>
             </div>
          )}
        </div>
      </main>

    </div>
  );
};

export default CourseBuilder;

