import { GoogleGenAI, Type } from "@google/genai";
import { Course, Module, Lesson, FileContext } from "../types";

const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean up JSON string if the model adds backticks
const cleanJson = (text: string) => {
  return text.replace(/^```json\s*/, "").replace(/\s*```$/, "");
};

// Helper to extract raw base64 from data URI if present
const getBase64Data = (dataUri: string) => {
  return dataUri.includes(',') ? dataUri.split(',')[1] : dataUri;
};

/**
 * Generates a course outline based on provided objective, structure, files, and audience.
 */
export const generateCourseOutline = async (
  courseObjective: string,
  userStructure: string,
  targetAudience: string,
  files: FileContext[],
  docUrl?: string,
  language: string = 'Português do Brasil'
): Promise<Course> => {
  const ai = getAiClient();

  const textPrompt = `Atue como um Arquiteto de Soluções e Designer Instrucional Sênior. Crie a estrutura JSON para um curso SCORM.

  OBJETIVO DO CURSO:
  ${courseObjective}

  ESTRUTURA SUGERIDA PELO USUÁRIO (Siga estritamente se houver):
  ${userStructure ? userStructure : "Não definida. Crie uma estrutura lógica de 2-3 Módulos."}

  PÚBLICO-ALVO:
  ${targetAudience}

  DOCUMENTAÇÃO OFICIAL DE REFERÊNCIA:
  ${docUrl ? docUrl : 'Nenhuma URL fornecida.'}

  INSTRUÇÕES:
  1. Analise os arquivos fornecidos (se houver) e a URL para extrair detalhes técnicos.
  2. A saída deve estar estritamente em ${language}.
  3. Organize em Módulos e Lições.
  4. Para cada lição, crie um 'imagePrompt' para um diagrama técnico (flat design) que explique o conceito.
  5. Forneça uma breve descrição do curso baseada no objetivo.`;

  const parts: any[] = [{ text: textPrompt }];

  files.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          modules: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                lessons: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      title: { type: Type.STRING },
                      imagePrompt: { type: Type.STRING, description: "Descrição técnica para diagrama ou ilustração." }
                    },
                    required: ["title", "imagePrompt"]
                  }
                }
              },
              required: ["title", "lessons"]
            }
          }
        },
        required: ["title", "description", "modules"]
      }
    }
  });

  const rawText = response.text || "{}";
  const data = JSON.parse(cleanJson(rawText));

  const course: Course = {
    id: crypto.randomUUID(),
    title: data.title,
    description: data.description,
    language: language,
    targetAudience: targetAudience,
    contextFiles: files,
    docUrl: docUrl,
    modules: data.modules.map((m: any) => ({
      id: crypto.randomUUID(),
      title: m.title,
      lessons: m.lessons.map((l: any) => ({
        id: crypto.randomUUID(),
        title: l.title,
        imagePrompt: l.imagePrompt,
        content: "", 
      }))
    }))
  };

  return course;
};

/**
 * Generates the HTML content for a specific lesson matching the Template style.
 * ENFORCES STRICT GROUNDING.
 */
export const generateLessonContent = async (
  lessonTitle: string, 
  course: Course
): Promise<string> => {
  const ai = getAiClient();

  const textPrompt = `Você é um Engenheiro de Software Sênior e redator técnico rigoroso.
  Escreva o conteúdo para a lição: "${lessonTitle}" do curso "${course.title}".

  REGRAS DE GROUNDING (CRÍTICO - LEIA COM ATENÇÃO):
  1. Use EXCLUSIVAMENTE as informações contidas nos arquivos anexados e na documentação oficial (${course.docUrl}).
  2. NÃO INVENTE, NÃO ALUCINE, NÃO USE CONHECIMENTO EXTERNO se não estiver corroborado pelos arquivos/URL.
  3. Se a informação não estiver disponível nas fontes, escreva explicitamente: "Esta informação não consta na documentação fornecida." e não tente preencher a lacuna.
  4. Seja fiel à terminologia exata usada nas fontes.

  CONTEXTO TÉCNICO (Público: ${course.targetAudience}):
  Use os arquivos anexados como única fonte da verdade.

  DIRETRIZES DE FORMATO (HTML):
  1. Retorne APENAS código HTML válido (div wrapper).
  2. Use classes Tailwind CSS.
  3. Estrutura profissional com <h2>, <h3>, <p>, <ul>.
  4. Use ícones FontAwesome.

  Certifique-se de que o conteúdo seja factualmente perfeito baseado apenas nas fontes.`;

  const parts: any[] = [{ text: textPrompt }];

  course.contextFiles.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      tools: [{ googleSearch: {} }], // Google Search is allowed to verify docs, but Prompt restricts invention.
      thinkingConfig: { thinkingBudget: 1024 }
    }
  });

  let cleanHtml = response.text || "";
  cleanHtml = cleanHtml.replace(/^```html\s*/, "").replace(/^```\s*/, "").replace(/\s*```$/, "");

  return cleanHtml;
};

/**
 * Generates an educational image using the Nano Banana model.
 */
export const generateLessonImage = async (imagePrompt: string): Promise<string | undefined> => {
  const ai = getAiClient();

  const refinedPrompt = `Tech illustration, flat design, vector style, white background, clean lines, corporate blue and slate colors. Diagrammatic representation of: ${imagePrompt}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: {
        parts: [{ text: refinedPrompt }]
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Image generation failed:", error);
    return undefined;
  }

  return undefined;
};

