                        </div>
                        {files.length > 0 && (
                          <div className="flex flex-wrap gap-2">
                            {files.map((file, idx) => (
                              <div key={idx} className="flex items-center gap-2 bg-indigo-50 text-indigo-700 px-3 py-1.5 rounded-lg border border-indigo-100 text-sm font-medium">
                                <span className="truncate max-w-[150px]">{file.name}</span>
                                <button type="button" onClick={(e) => {e.stopPropagation(); removeFile(idx);}} className="text-indigo-400 hover:text-indigo-600"><TrashIcon /></button>
                              </div>
                            ))}
                          </div>
                        )}
                     </div>

                     <button 
                       type="submit" 
                       disabled={loading || !courseObjective.trim()} 
                       className={`w-full py-4 rounded-xl font-bold text-lg shadow-lg hover:shadow-xl hover:-translate-y-0.5 transition-all flex items-center justify-center gap-2 ${loading ? 'bg-slate-300 text-slate-500 cursor-not-allowed' : 'bg-gradient-to-r from-indigo-600 to-blue-600 text-white'}`}
                     >
                       {loading ? (
                         <><div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> <span>Analisando Fontes e Criando Estrutura...</span></>
                       ) : (
                         <><SparklesIcon /> <span>Gerar Curso</span></>
                       )}
                     </button>
                  </form>
               </div>
            </div>

            <div className="mt-8 text-center text-slate-400 text-sm">
               Powered by Google Gemini Nano • Strict Grounding Enabled
            </div>
         </div>
      </div>
    );
  }

