interface CourseBuilderProps {}

const CourseBuilder: React.FC<CourseBuilderProps> = () => {
  // Input State
  const [courseObjective, setCourseObjective] = useState('');
  const [courseStructure, setCourseStructure] = useState('');
  const [targetAudience, setTargetAudience] = useState('');
  const [docUrl, setDocUrl] = useState('');
  const [files, setFiles] = useState<FileContext[]>([]);
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // App State
  const [course, setCourse] = useState<Course | null>(null);
  const [activeLessonId, setActiveLessonId] = useState<string | null>(null);
  const [generatingImageId, setGeneratingImageId] = useState<string | null>(null);

  // Editor State
  const [isEditing, setIsEditing] = useState(false);
  const [mediaInput, setMediaInput] = useState('');
  const [mediaType, setMediaType] = useState<'video' | 'drive' | null>(null);

  // Mermaid Initialization
  useEffect(() => {
    if (activeLessonId && !isEditing) {
      // @ts-ignore
      if (window.mermaid) {
        // @ts-ignore
        window.mermaid.init(undefined, document.querySelectorAll('.mermaid'));
      }
    }
  }, [activeLessonId, isEditing, course]);

  // Load Mermaid Script
  useEffect(() => {
    const script = document.createElement('script');
    script.src = "https://cdn.jsdelivr.net/npm/mermaid/dist/mermaid.min.js";
    script.onload = () => {
      // @ts-ignore
      window.mermaid.initialize({ startOnLoad: true, theme: 'neutral' });
    };
    document.head.appendChild(script);
  }, []);

  // --- File Handlers ---
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: FileContext[] = [];
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const base64 = await convertFileToBase64(file);
        newFiles.push({
          name: file.name,
          mimeType: file.type,
          data: base64
        });
      }
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const convertFileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  // --- Course Generation Handlers ---
  const handleCreateCourse = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!courseObjective.trim()) return;

    setLoading(true);
    try {
      const generatedCourse = await GeminiService.generateCourseOutline(
        courseObjective,
        courseStructure,
        targetAudience, 
        files,
        docUrl
      );
      setCourse(generatedCourse);

      if (generatedCourse.modules.length > 0 && generatedCourse.modules[0].lessons.length > 0) {
        setActiveLessonId(generatedCourse.modules[0].lessons[0].id);
        fetchLessonContent(generatedCourse.modules[0].lessons[0], generatedCourse);
      }
    } catch (error) {
      console.error("Error creating course:", error);
      alert("Falha ao criar a estrutura do curso. Por favor, tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  const fetchLessonContent = async (lesson: Lesson, currentCourse: Course) => {
    if (lesson.content) return;
    updateLesson(lesson.id, { isLoading: true });
    try {
      const content = await GeminiService.generateLessonContent(lesson.title, currentCourse);
      updateLesson(lesson.id, { content, isLoading: false });
    } catch (error) {
      updateLesson(lesson.id, { isLoading: false, content: "<div class='p-8 text-red-500'>Erro ao gerar conteúdo. Verifique se as informações estão na documentação fornecida.</div>" });
    }
  };

  const generateImageForLesson = async (lesson: Lesson) => {
    if (!lesson.imagePrompt) return;
    setGeneratingImageId(lesson.id);
    try {
      const imageUrl = await GeminiService.generateLessonImage(lesson.imagePrompt);
      if (imageUrl) {
        updateLesson(lesson.id, { imageUrl });
      }
    } finally {
      setGeneratingImageId(null);
    }
  };

  const updateLesson = (lessonId: string, updates: Partial<Lesson>) => {
    setCourse(prev => {
      if (!prev) return null;
      const newModules = prev.modules.map(mod => ({
        ...mod,
        lessons: mod.lessons.map(les => 
          les.id === lessonId ? { ...les, ...updates } : les
        )
      }));
      return { ...prev, modules: newModules };
    });
  };

  // --- Editor Handlers ---
  const handleContentChange = (newContent: string) => {
    if (activeLessonId) {
      updateLesson(activeLessonId, { content: newContent });
    }
  };

  // Improved ID extraction for robustness
  const getYoutubeId = (url: string) => {
    const regExp = /^.*((youtu.be\/)|(v\/)|(\/u\/\w\/)|(embed\/)|(watch\?))\??v?=?([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[7].length === 11) ? match[7] : null;
  };

  const insertMedia = () => {
    if (!mediaInput || !activeLessonId) return;
    const lesson = getActiveLesson();
    if (!lesson) return;

    let snippet = '';

    if (mediaType === 'video') {
      const videoId = getYoutubeId(mediaInput);

      if (videoId) {
        const origin = window.location.origin;
        snippet = `
          <div class="my-8 bg-white p-2 rounded-xl border border-slate-200 shadow-sm">
             <div class="aspect-video-wrapper bg-slate-100 relative pb-[56.25%] h-0 overflow-hidden rounded-lg">
                <iframe 
                  src="https://www.youtube.com/embed/${videoId}?rel=0&modestbranding=1&origin=${origin}" 
                  class="absolute top-0 left-0 w-full h-full" 
                  frameborder="0" 
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" 
                  referrerpolicy="strict-origin-when-cross-origin" 
                  allowfullscreen>
                </iframe>
             </div>
             <div class="mt-2 text-right">
                <a href="https://www.youtube.com/watch?v=${videoId}" target="_blank" rel="noopener noreferrer" class="text-xs text-blue-500 hover:underline"><i class="fas fa-external-link-alt"></i> Assistir no YouTube (caso o vídeo não carregue)</a>
             </div>
          </div>
        `;
      } else {
        alert("Link do YouTube inválido.");
        return;
      }
    } else if (mediaType === 'drive') {
      snippet = `
        <div class="my-6 p-4 bg-blue-50 border border-blue-200 rounded-xl flex items-center gap-4 hover:bg-blue-100 transition">
           <div class="w-10 h-10 bg-blue-600 rounded-full flex items-center justify-center text-white"><i class="fas fa-cloud-download-alt"></i></div>
           <div class="flex-1">
             <h4 class="font-bold text-slate-800">Material Complementar</h4>
             <p class="text-sm text-slate-600">Acesse o arquivo no Google Drive.</p>
           </div>
           <a href="${mediaInput}" target="_blank" class="px-4 py-2 bg-white text-blue-600 font-bold rounded-lg shadow-sm hover:shadow-md transition">Acessar</a>
        </div>
      `;
    }

    if (snippet) {
      updateLesson(activeLessonId, { content: (lesson.content || '') + snippet });
    }

    setMediaInput('');
    setMediaType(null);
  };

  // --- Export Logic ---
  const handleExport = () => {
    if (!course) return;

    // Flatten structure for the template
    let flatIndex = 0;
    const courseData: any[] = [];

    // Intro Slide
    courseData.push({
      id: flatIndex++,
      title: "Introdução do Curso",
      module: "Visão Geral", // Added module grouping
      type: "content",
      content: `
         <div class="flex flex-col md:flex-row h-full">
            <div class="md:w-1/2 p-8 lg:p-12 flex flex-col justify-center bg-slate-50 border-r border-slate-100">
                  <span class="text-blue-600 font-bold tracking-wider text-sm mb-2 uppercase">Visão Geral</span>
                  <h2 class="text-4xl lg:text-5xl font-bold text-slate-900 mb-6 leading-tight">${course.title}</h2>
                  <p class="text-lg text-slate-600 leading-relaxed mb-8">${course.description}</p>
            </div>
            <div class="md:w-1/2 relative overflow-hidden bg-slate-900 flex items-center justify-center">
                <div class="text-white text-center p-10">
                   <i class="fas fa-rocket text-6xl mb-4 text-blue-400"></i>
                   <h3 class="text-2xl font-bold">Comece sua jornada</h3>
                </div>
            </div>
         </div>
      `
    });

    // Modules & Lessons
    course.modules.forEach(mod => {
      mod.lessons.forEach(lesson => {
        let finalContent = lesson.content || "";
        // Inject Image if exists
        if (lesson.imageUrl && !finalContent.includes('<img')) {
             finalContent = `
               <div class="p-8 lg:p-12 h-full custom-scroll overflow-y-auto">
                 <div class="max-w-4xl mx-auto">
                   <div class="mb-8 rounded-xl overflow-hidden shadow-md border border-slate-200">
                      <img src="${lesson.imageUrl}" alt="${lesson.title}" class="w-full object-cover max-h-[300px]" />
                   </div>
                   ${finalContent.replace('<div class="p-8 lg:p-12 h-full custom-scroll overflow-y-auto">', '').replace(/<\/div>$/, '')} 
                 </div>
               </div>
             `;
        }

        courseData.push({
          id: flatIndex++,
          title: lesson.title,
          module: mod.title, // Added module grouping
          type: "content",
          content: finalContent
        });
      });
    });

    // Conclusion Slide
    courseData.push({
      id: flatIndex++,
      title: "Conclusão",
      module: "Encerramento", // Added module grouping
      type: "final",
      content: `
        <div class="h-full flex flex-col items-center justify-center text-center p-8 bg-gradient-to-b from-white to-blue-50">
            <div class="mb-6 relative">
                <div class="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center text-5xl text-white shadow-xl animate-[bounce_2s_infinite]">
                    <i class="fas fa-trophy"></i>
                </div>
            </div>
            <h2 class="text-4xl font-bold text-slate-900 mb-4">Curso Concluído!</h2>
            <p class="text-lg text-slate-600 max-w-md mb-8">
                Parabéns! Você completou o treinamento sobre ${course.title}.
            </p>
            <button onclick="exitCourse()" class="px-8 py-4 magalu-gradient text-white rounded-xl font-bold shadow-lg shadow-blue-500/30 hover:scale-105 transition transform">
                Finalizar e Sair
            </button>
        </div>
      `
    });

    const template = getScormTemplate(JSON.stringify(courseData), course.title);
    const blob = new Blob([template], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `SCORM_${course.title.replace(/\s+/g, '_')}.html`;
    a.click();
  };

  // --- Helper: Scorm Template String ---
  // Major update: Added Sidebar logic, Responsive layout, and grouping logic in JS.
  // CRITICAL UPDATE: Included Robust Mock API and Initialization from reference to prevent Cross-Origin errors.
  const getScormTemplate = (dataJson: string, title: string) => `
<!DOCTYPE html>
<html lang="pt-BR">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${title}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css" rel="stylesheet">
    <script src="https://cdn.jsdelivr.net/npm/canvas-confetti@1.6.0/dist/confetti.browser.min.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/mermaid/dist/mermaid.min.js"></script>
    <style>
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=Fira+Code:wght@400;500&display=swap');

        body { font-family: 'Inter', sans-serif; background-color: #f8fafc; overflow: hidden; user-select: none; }
        .magalu-gradient { background: linear-gradient(135deg, #0086FF 0%, #0050e6 100%); }
        .fade-enter { animation: fadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }

        /* Scrollbar Styling */
        .custom-scroll::-webkit-scrollbar { width: 6px; height: 6px; }
        .custom-scroll::-webkit-scrollbar-track { background: transparent; }
        .custom-scroll::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 10px; }
        .custom-scroll::-webkit-scrollbar-thumb:hover { background: #94a3b8; }

        /* Sidebar Animations */
        #sidebar { transition: transform 0.3s cubic-bezier(0.4, 0, 0.2, 1); }
        .sidebar-open { transform: translateX(0); }
        .sidebar-closed { transform: translateX(-100%); }
        @media (min-width: 768px) {
            .sidebar-closed { transform: translateX(0); } /* Always open on desktop for now, or implement collapsible logic if needed */
        }

        .active-lesson { background-color: #eff6ff; color: #1d4ed8; border-right: 3px solid #2563eb; }

        /* Loader */
        #app-loader {
            position: fixed; top: 0; left: 0; width: 100%; height: 100%;
            background: #ffffff; z-index: 100;
            display: flex; flex-direction: column; align-items: center; justify-content: center;
            transition: opacity 0.5s ease;
        }
    </style>
</head>
<body class="h-screen flex flex-col text-slate-800 bg-slate-50">

    <!-- Preloader -->
    <div id="app-loader">
        <div class="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
        <div class="text-slate-500 font-medium animate-pulse">Carregando conteúdo...</div>
    </div>

    <!-- Header -->
    <header class="bg-white border-b border-slate-200 h-16 flex items-center justify-between px-4 z-30 shrink-0 shadow-sm relative">
        <div class="flex items-center gap-3">
             <button onclick="toggleSidebar()" class="p-2 text-slate-500 hover:bg-slate-100 rounded-lg transition-colors md:hidden">
                <i class="fas fa-bars text-lg"></i>
             </button>
             <div>
                <h1 class="font-bold text-slate-800 truncate max-w-[180px] md:max-w-md leading-tight text-sm md:text-base">${title}</h1>
                <p class="text-[10px] text-slate-500 font-bold uppercase tracking-wider hidden md:block">Ambiente de Aprendizagem</p>
             </div>
        </div>
        <div class="flex items-center gap-4">
             <div class="hidden md:flex flex-col items-end w-32 lg:w-48">
                <div class="flex justify-between w-full text-[10px] font-bold text-slate-500 mb-1"><span>Progresso</span><span id="progress-text">0%</span></div>
                <div class="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden"><div id="progress-bar" class="h-full magalu-gradient transition-all duration-500 ease-out" style="width: 0%"></div></div>
            </div>
            <img src="https://media.licdn.com/dms/image/v2/D4D0BAQGlkyJOKvz6WQ/company-logo_200_200/company-logo_200_200/0/1718300941618/extremedigitalsolutions_logo?e=2147483647&v=beta&t=fUKXMHsSI8xi-6Xa5mVIMCWMPQ7wlQUPQZud_XASSls" class="h-8 md:h-10 w-auto rounded object-contain" alt="EDS Logo">
            <button onclick="exitCourse()" class="text-slate-400 hover:text-red-500 transition-colors p-2 rounded-full hover:bg-red-50" title="Sair"><i class="fas fa-power-off"></i></button>
        </div>
    </header>

    <!-- Main Workspace -->
    <div class="flex-1 flex overflow-hidden relative">

        <!-- Sidebar Navigation -->
        <aside id="sidebar" class="absolute inset-y-0 left-0 z-20 w-72 bg-white border-r border-slate-200 flex flex-col sidebar-closed md:relative md:transform-none shadow-xl md:shadow-none">
            <div class="p-4 border-b border-slate-100 bg-slate-50 flex items-center justify-between md:justify-start">
                <span class="text-xs font-bold text-slate-400 uppercase tracking-wider">Conteúdo do Curso</span>
                <button onclick="toggleSidebar()" class="md:hidden text-slate-400 hover:text-slate-600"><i class="fas fa-times"></i></button>
            </div>
            <nav id="toc" class="flex-1 overflow-y-auto p-2 space-y-1 custom-scroll pb-20"></nav>
        </aside>

        <!-- Overlay for mobile sidebar -->
        <div id="sidebar-overlay" onclick="toggleSidebar()" class="fixed inset-0 bg-black/20 z-10 hidden transition-opacity opacity-0"></div>

        <!-- Content Area -->
        <main class="flex-1 overflow-hidden relative flex flex-col bg-slate-100/50">
            <div class="flex-1 overflow-y-auto p-0 md:p-6 custom-scroll scroll-smooth" id="scroll-container">
                 <div id="content-area" class="w-full max-w-5xl mx-auto bg-white min-h-full md:min-h-[calc(100vh-180px)] md:shadow-sm md:border md:border-slate-200 md:rounded-xl overflow-hidden fade-enter relative pb-10">
                    <!-- Content injected here -->
                 </div>
            </div>

            <!-- Sticky Navigation Footer -->
            <div class="h-20 bg-white border-t border-slate-200 shrink-0 px-4 md:px-8 flex items-center justify-between z-10 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
                 <button id="btn-prev" onclick="prevSlide()" class="group flex items-center gap-2 px-4 py-2 rounded-lg text-slate-600 font-semibold hover:bg-slate-100 disabled:opacity-40 disabled:hover:bg-transparent transition-all text-sm md:text-base">
                    <i class="fas fa-arrow-left group-hover:-translate-x-1 transition-transform"></i>
                    <span>Anterior</span>
                 </button>

                 <div class="bg-slate-100 px-4 py-1.5 rounded-full text-xs font-bold text-slate-500 tracking-wider hidden sm:block">
                    <span id="slide-indicator">1 / 1</span>
                 </div>

                 <button id="btn-next" onclick="nextSlide()" class="group flex items-center gap-2 px-6 py-2.5 rounded-lg magalu-gradient text-white font-semibold hover:shadow-lg disabled:opacity-50 transition-all text-sm md:text-base">
                    <span>Próximo</span>
                    <i class="fas fa-arrow-right group-hover:translate-x-1 transition-transform"></i>
                 </button>
            </div>
        </main>
    </div>

    <script>
        const courseData = ${dataJson};

        // --- MOCK LMS API (Correção para o erro de Cross-Origin) ---
        // Implementação robusta fornecida na referência para permitir execução local e prevenir bloqueios
        window.API = {
            LMSInitialize: function(param) {
                console.log("[LMS Mock] LMSInitialize chamado.");
                return "true";
            },
            LMSFinish: function(param) {
                console.log("[LMS Mock] LMSFinish chamado.");
                return "true";
            },
            LMSGetValue: function(element) {
                console.log("[LMS Mock] LMSGetValue: " + element);
                if (element === "cmi.core.student_id") return "TEST_USER_ID";
                if (element === "cmi.core.student_name") return "Teste Utilizador";
                return "";
            },
            LMSSetValue: function(element, value) {
                console.log("[LMS Mock] LMSSetValue: " + element + " = " + value);
                return "true";
            },
            LMSCommit: function(param) {
                console.log("[LMS Mock] LMSCommit chamado.");
                return "true";
            },
            LMSGetLastError: function() { return "0"; },
            LMSGetErrorString: function(code) { return "No error"; },
            LMSGetDiagnostic: function(code) { return "No error"; }
        };

        // --- SCORM LOGIC ---
        const scorm = {
            api: null, version: null, startTime: new Date(),
            init: function() {
                try {
                    let parentWin = window.parent;
                    // First try to find API in parent
                    if (parentWin && parentWin.API_1484_11) { 
                        this.api = parentWin.API_1484_11; 
                        this.version = "2004"; 
                        this.api.Initialize(""); 
                        console.log("SCORM 2004 API Found");
                    } 
                    else if (parentWin && parentWin.API) { 
                        this.api = parentWin.API; 
                        this.version = "1.2"; 
                        this.api.LMSInitialize(""); 
                        console.log("SCORM 1.2 API Found");
                    }
                    else { 
                        // FALLBACK TO MOCK API (Self-contained mode)
                        console.log("No LMS API found. Using Local Mock API for standalone mode.");
                        this.api = window.API; // Use the local mock
                        this.version = "1.2"; // Assume 1.2 for mock
                        this.api.LMSInitialize("");
                    }

                    if(this.api) this.setStatus("incomplete");
                } catch (e) { 
                    console.warn("SCORM Init Error:", e); 
                    // Fallback purely local
                    this.api = window.API;
                }
            },
            setStatus: function(s) { if(!this.api) return; this.version==="2004" ? this.api.SetValue("cmi.completion_status", s==='passed'?'completed':s) : this.api.LMSSetValue("cmi.core.lesson_status", s); this.commit(); },
            setBookmark: function(l) { if(!this.api) return; this.version==="2004" ? this.api.SetValue("cmi.location", l) : this.api.LMSSetValue("cmi.core.lesson_location", l); this.commit(); },
            getBookmark: function() { if(!this.api) return null; return this.version==="2004" ? this.api.GetValue("cmi.location") : this.api.LMSGetValue("cmi.core.lesson_location"); },
            commit: function() { if(this.api) this.version==="2004" ? this.api.Commit("") : this.api.LMSCommit(""); },
            finish: function() { if(this.api) this.version==="2004" ? this.api.Terminate("") : this.api.LMSFinish(""); }
        };

        let currentSlide = 0;

        // --- UI LOGIC ---
        function initApp() {
            scorm.init();
            renderSidebar();

            const bookmark = scorm.getBookmark();
            if (bookmark && parseInt(bookmark) > 0) currentSlide = parseInt(bookmark);

            renderSlide(currentSlide);
            setupMobileMenu();

            // Remove Loader
            setTimeout(() => {
                const loader = document.getElementById('app-loader');
                loader.style.opacity = '0';
                setTimeout(() => loader.remove(), 500);
            }, 800);
        }

        function renderSidebar() {
            const toc = document.getElementById('toc');
            let currentModule = null;

            courseData.forEach((item, index) => {
                // Check if new module header is needed
                if (item.module !== currentModule) {
                    currentModule = item.module;
                    const modHeader = document.createElement('div');
                    modHeader.className = "px-3 py-2 mt-4 text-[10px] font-bold text-slate-400 uppercase tracking-wider";
                    modHeader.innerText = currentModule || "Geral";
                    toc.appendChild(modHeader);
                }

                // Lesson Item
                const btn = document.createElement('button');
                btn.id = "toc-item-" + index;
                btn.className = "w-full text-left px-3 py-2.5 rounded-lg text-sm transition-all flex items-center gap-3 text-slate-600 hover:bg-slate-50 hover:text-slate-900";
                btn.onclick = () => {
                    renderSlide(index);
                    if(window.innerWidth < 768) toggleSidebar();
                };

                const icon = document.createElement('i');
                icon.className = item.type === 'final' ? "fas fa-flag-checkered w-4" : "fas fa-book-open w-4";

                const text = document.createElement('span');
                text.className = "truncate";
                text.innerText = item.title;

                btn.appendChild(icon);
                btn.appendChild(text);
                toc.appendChild(btn);
            });
        }

        function renderSlide(index) {
            currentSlide = index;
            const container = document.getElementById("content-area");
            const data = courseData[index];

            // Animation reset
            container.classList.remove("fade-enter");
            void container.offsetWidth; 
            container.classList.add("fade-enter");

            container.innerHTML = data.content;
            document.getElementById("scroll-container").scrollTop = 0;

            // Mermaid Re-init
            if(window.mermaid) {
                setTimeout(() => { mermaid.init(undefined, document.querySelectorAll('.mermaid')); }, 100);
            }

            updateControls(index, data.type);
            updateProgress();
            updateSidebarActiveState(index);
            scorm.setBookmark(index);
        }

        function updateSidebarActiveState(index) {
            document.querySelectorAll('#toc button').forEach(b => {
                b.classList.remove('active-lesson');
                b.classList.add('text-slate-600');
            });
            const active = document.getElementById("toc-item-" + index);
            if(active) {
                active.classList.add('active-lesson');
                active.classList.remove('text-slate-600');
                active.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
            }
        }

        function updateControls(index, type) {
            document.getElementById("slide-indicator").innerText = (index + 1) + " / " + courseData.length;
            document.getElementById("btn-prev").disabled = index === 0;
            const btnNext = document.getElementById("btn-next");
            if (type === "final") {
                btnNext.style.display = "none";
                scorm.setStatus("passed");
            } else { 
                btnNext.style.display = "flex"; 
                btnNext.disabled = index === courseData.length - 1; 
            }
        }

        function updateProgress() {
            const p = ((currentSlide + 1) / courseData.length) * 100;
            document.getElementById("progress-bar").style.width = p + "%";
            document.getElementById("progress-text").innerText = Math.round(p) + "%";
        }

        // --- Sidebar Toggle for Mobile ---
        function toggleSidebar() {
            const sidebar = document.getElementById('sidebar');
            const overlay = document.getElementById('sidebar-overlay');
            const isClosed = sidebar.classList.contains('sidebar-closed');

            if (isClosed) {
                sidebar.classList.remove('sidebar-closed');
                overlay.classList.remove('hidden');
                setTimeout(() => overlay.classList.remove('opacity-0'), 10);
            } else {
                sidebar.classList.add('sidebar-closed');
                overlay.classList.add('opacity-0');
                setTimeout(() => overlay.classList.add('hidden'), 300);
            }
        }

        function setupMobileMenu() {
            // Ensure sidebar resets on resize
            window.addEventListener('resize', () => {
                if(window.innerWidth >= 768) {
                    document.getElementById('sidebar').classList.remove('sidebar-closed');
                    document.getElementById('sidebar-overlay').classList.add('hidden');
                } else {
                    document.getElementById('sidebar').classList.add('sidebar-closed');
                }
            });
        }

        function nextSlide() { if (currentSlide < courseData.length - 1) renderSlide(currentSlide + 1); }
        function prevSlide() { if (currentSlide > 0) renderSlide(currentSlide - 1); }
        function exitCourse() { scorm.finish(); window.close(); }

        window.onload = initApp;
    </script>
</body>
</html>`;

  // --- Render Navigation ---
  const handleLessonSelect = (lesson: Lesson) => {
    setActiveLessonId(lesson.id);
    if (!lesson.content && course) {
      fetchLessonContent(lesson, course);
    }
  };

  const getActiveLesson = () => {
    if (!course) return null;
    for (const mod of course.modules) {
      for (const les of mod.lessons) {
        if (les.id === activeLessonId) return les;
      }
    }
    return null;
  };

  const activeLesson = getActiveLesson();

  // --- View: Initial Form (Wizard Style) ---
  if (!course) {
    return (
