import { GoogleGenAI, Type } from "@google/genai";
import { Course, Module, Lesson, FileContext } from "../types";

const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean up JSON string if the model adds backticks
const cleanJson = (text: string) => {
  return text.replace(/^```json\s*/, "").replace(/\s*```$/, "");
};

// Helper to extract raw base64 from data URI if present
const getBase64Data = (dataUri: string) => {
  return dataUri.includes(',') ? dataUri.split(',')[1] : dataUri;
};

/**
 * Generates a course outline based on provided objective, structure, files, and audience.
 */
export const generateCourseOutline = async (
  courseObjective: string,
  userStructure: string,
  targetAudience: string,
  files: FileContext[],
  docUrl?: string,
  language: string = 'Português do Brasil'
): Promise<Course> => {
  const ai = getAiClient();

  const textPrompt = `Atue como um Arquiteto de Soluções e Tech Lead. Crie a estrutura JSON para uma base de conhecimento técnica (formato Curso/Wiki).

  OBJETIVO DA BASE DE CONHECIMENTO:
  ${courseObjective}

  ESTRUTURA SUGERIDA PELO USUÁRIO (Siga estritamente se houver):
  ${userStructure ? userStructure : "Não definida. Crie uma estrutura lógica de profundidade técnica."}

  PÚBLICO-ALVO:
  ${targetAudience}

  DOCUMENTAÇÃO OFICIAL DE REFERÊNCIA:
  ${docUrl ? docUrl : 'Nenhuma URL fornecida.'}

  INSTRUÇÕES:
  1. Analise os arquivos e URL para extrair a taxonomia técnica.
  2. A saída deve estar estritamente em ${language}.
  3. Organize em Módulos (Grandes Temas) e Lições (Artigos Técnicos).
  4. Para cada lição, crie um 'imagePrompt' para um diagrama de arquitetura complexo (flat design) que explique o fluxo de dados ou infraestrutura física.
  5. O foco é PROFUNDIDADE TÉCNICA, não superficialidade.`;

  const parts: any[] = [{ text: textPrompt }];

  files.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          modules: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                lessons: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      title: { type: Type.STRING },
                      imagePrompt: { type: Type.STRING, description: "Descrição técnica detalhada para diagrama de arquitetura." }
                    },
                    required: ["title", "imagePrompt"]
                  }
                }
              },
              required: ["title", "lessons"]
            }
          }
        },
        required: ["title", "description", "modules"]
      }
    }
  });

  const rawText = response.text || "{}";
  const data = JSON.parse(cleanJson(rawText));

  const course: Course = {
    id: crypto.randomUUID(),
    title: data.title,
    description: data.description,
    language: language,
    targetAudience: targetAudience,
    contextFiles: files,
    docUrl: docUrl,
    modules: data.modules.map((m: any) => ({
      id: crypto.randomUUID(),
      title: m.title,
      lessons: m.lessons.map((l: any) => ({
        id: crypto.randomUUID(),
        title: l.title,
        imagePrompt: l.imagePrompt,
        content: "", 
      }))
    }))
  };

  return course;
};

/**
 * Generates the HTML content for a specific lesson matching the Template style.
 * ENFORCES STRICT GROUNDING + HIGH DENSITY DOCUMENTATION STYLE.
 */
export const generateLessonContent = async (
  lessonTitle: string, 
  course: Course
): Promise<string> => {
  const ai = getAiClient();

  const textPrompt = `Você é um Principal Software Engineer e Technical Writer responsável pela documentação oficial de um produto complexo.
  Escreva um ARTIGO TÉCNICO PROFUNDO (Estilo Wiki/Doc) para o tópico: "${lessonTitle}" do curso "${course.title}".

  MUDANÇA DE PARADIGMA (LEIA COM ATENÇÃO):
  1. MODELO DOC/WIKI: NÃO crie slides, listas curtas ou texto resumido. O formato deve ser um documento técnico de rolagem vertical contínua, denso e detalhado.
  2. DENSIDADE TÉCNICA (FIRST PRINCIPLES): Explique o "PORQUÊ" e a "ARQUITETURA INTERNA", não apenas o "COMO".
     - Exemplo Ruim: "Para conectar SSH use o comando X."
     - Exemplo Bom: "A conexão SSH inicia com um handshake TCP, seguido pela negociação de algoritmos criptográficos (Key Exchange). O servidor envia sua chave pública (host key) para verificação de identidade..."
     - Exemplo Ruim: "A região tem várias zonas."
     - Exemplo Bom: "A arquitetura física de uma Região consiste em múltiplos datacenters isolados (Zonas de Disponibilidade) conectados por fibra ótica de baixa latência e alta largura de banda, garantindo replicação síncrona..."
  3. Formatacao: Use <h2>, <h3> para estruturar o texto longo. Use parágrafos explicativos robustos. Use blocos de código para exemplos ou logs. Use <div class="bg-blue-50 p-4 border-l-4 border-blue-500"> para notas técnicas importantes.

  REGRAS DE GROUNDING (CRÍTICO):
  1. Use EXCLUSIVAMENTE as informações contidas nos arquivos anexados e na documentação oficial (${course.docUrl}).
  2. NÃO INVENTE fatos. Se aprofunde nos conceitos teóricos (SO, Redes, Hardware) que sustentam o que está nos documentos.

  OBRIGATÓRIO - SEÇÃO DE REFERÊNCIAS:
  Ao final, inclua <div class="mt-12 border-t border-slate-200 pt-6"> com "Referências e Fontes Oficiais".
  - Link para ${course.docUrl} se existir.

  CONTEXTO TÉCNICO (Público: ${course.targetAudience}):
  Trate o leitor como um engenheiro inteligente que precisa entender o funcionamento interno.

  DIRETRIZES DE FORMATO (HTML):
  1. Retorne APENAS código HTML válido (div wrapper).
  2. Use classes Tailwind CSS.
  3. Texto justificado ou à esquerda, fonte legível, layout de artigo.

  Gere um conteúdo extenso, educativo e tecnicamente impecável.`;

  const parts: any[] = [{ text: textPrompt }];

  course.contextFiles.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview", // Upgraded to Pro for deeper reasoning and text generation
    contents: { parts },
    config: {
      tools: [{ googleSearch: {} }],
      thinkingConfig: { thinkingBudget: 4096 } // Increased budget for architectural reasoning
    }
  });

  let cleanHtml = response.text || "";
  cleanHtml = cleanHtml.replace(/^```html\s*/, "").replace(/^```\s*/, "").replace(/\s*```$/, "");

  return cleanHtml;
};

/**
 * Generates an educational image using the Nano Banana model.
 */
export const generateLessonImage = async (imagePrompt: string): Promise<string | undefined> => {
  const ai = getAiClient();

  // Prompt refinado para diagramas técnicos de arquitetura
  const refinedPrompt = `Technical architecture diagram, blueprint style, isometric view or flat schematic. Detailed representation of: ${imagePrompt}. White background, corporate blue/slate color palette, clean vector lines, high resolution, engineering drawing style.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: {
        parts: [{ text: refinedPrompt }]
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Image generation failed:", error);
    return undefined;
  }

  return undefined;
};

