import { GoogleGenAI, Type } from "@google/genai";
import { Course, Module, Lesson, FileContext } from "../types";

const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean up JSON string if the model adds backticks
const cleanJson = (text: string) => {
  return text.replace(/^```json\s*/, "").replace(/\s*```$/, "");
};

// Helper to extract raw base64 from data URI if present
const getBase64Data = (dataUri: string) => {
  return dataUri.includes(',') ? dataUri.split(',')[1] : dataUri;
};

/**
 * Generates a course outline based on provided objective, structure, files, and audience.
 * NOW USES GOOGLE SEARCH TOOL TO READ DOCUMENTATION IN REAL-TIME.
 */
export const generateCourseOutline = async (
  courseObjective: string,
  userStructure: string,
  targetAudience: string,
  files: FileContext[],
  docUrl?: string,
  language: string = 'Português do Brasil'
): Promise<Course> => {
  const ai = getAiClient();

  const textPrompt = `Atue como um Arquiteto de Soluções e Tech Lead.

  METODOLOGIA OBRIGATÓRIA (REAL-TIME BROWSING):
  1. O usuário forneceu a seguinte FONTE OFICIAL (URL): ${docUrl ? docUrl : 'Nenhuma (Use apenas arquivos)'}.
  2. AÇÃO: Use a ferramenta de busca (Google Search) AGORA para acessar e ler a estrutura atual desta documentação.
  3. DADOS ATUALIZADOS: Ignore seu conhecimento de treinamento se ele diferir do que você encontrar online agora. Baseie a estrutura no que está "vivo" no site.

  OBJETIVO DO CURSO/WIKI:
  ${courseObjective}

  ESTRUTURA SUGERIDA PELO USUÁRIO:
  ${userStructure ? userStructure : "Não definida. Crie uma estrutura baseada na documentação lida."}

  PÚBLICO-ALVO:
  ${targetAudience}

  INSTRUÇÕES DE SAÍDA:
  1. Analise os arquivos e a URL (via Search) para extrair a taxonomia técnica exata.
  2. A saída deve estar estritamente em ${language}.
  3. Organize em Módulos e Lições.
  4. Para cada lição, crie um 'imagePrompt' para um diagrama de arquitetura técnica.`;

  const parts: any[] = [{ text: textPrompt }];

  files.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      tools: [{ googleSearch: {} }], // Enable real-time reading for Outline
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          modules: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                lessons: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      title: { type: Type.STRING },
                      imagePrompt: { type: Type.STRING, description: "Descrição técnica detalhada para diagrama de arquitetura." }
                    },
                    required: ["title", "imagePrompt"]
                  }
                }
              },
              required: ["title", "lessons"]
            }
          }
        },
        required: ["title", "description", "modules"]
      }
    }
  });

  const rawText = response.text || "{}";
  const data = JSON.parse(cleanJson(rawText));

  const course: Course = {
    id: crypto.randomUUID(),
    title: data.title,
    description: data.description,
    language: language,
    targetAudience: targetAudience,
    contextFiles: files,
    docUrl: docUrl,
    modules: data.modules.map((m: any) => ({
      id: crypto.randomUUID(),
      title: m.title,
      lessons: m.lessons.map((l: any) => ({
        id: crypto.randomUUID(),
        title: l.title,
        imagePrompt: l.imagePrompt,
        content: "", 
      }))
    }))
  };

  return course;
};

/**
 * Generates the HTML content for a specific lesson.
 * ENFORCES STRICT REAL-TIME READING OF THE URL via Google Search Grounding.
 */
export const generateLessonContent = async (
  lessonTitle: string, 
  course: Course
): Promise<string> => {
  const ai = getAiClient();

  const textPrompt = `Você é um Principal Technical Writer.

  METODOLOGIA DE TRABALHO (IMPORTANTE):
  1. FONTE DA VERDADE: O usuário forneceu a URL oficial: ${course.docUrl}.
  2. AÇÃO: Use a ferramenta de busca para LER esta página/seção específica AGORA.
  3. SEM ALUCINAÇÃO: Não invente comandos ou configurações. Se a documentação oficial mudou ontem, você deve usar a versão de ontem (que você acabou de ler), e não a de meses atrás.
  4. OBJETIVO: Escrever um ARTIGO TÉCNICO PROFUNDO (Estilo Wiki) sobre "${lessonTitle}".

  CONTEXTO:
  Curso: "${course.title}"
  Público: "${course.targetAudience}"

  ESTRUTURA DO CONTEÚDO (DOC/WIKI):
  - Explique o "PORQUÊ" e a "ARQUITETURA" (First Principles).
  - Use exemplos de código reais extraídos da leitura da URL.
  - Use <h2>, <h3>, <pre><code> para formatar.
  - Seção de Referências Obrigatória: Inclua o link da fonte lida.

  Gere apenas o HTML do conteúdo (dentro de uma div). Use Tailwind CSS.`;

  const parts: any[] = [{ text: textPrompt }];

  course.contextFiles.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview", 
    contents: { parts },
    config: {
      tools: [{ googleSearch: {} }], // Strict requirement for real-time reading
      thinkingConfig: { thinkingBudget: 4096 }
    }
  });

  let cleanHtml = response.text || "";
  cleanHtml = cleanHtml.replace(/^```html\s*/, "").replace(/^```\s*/, "").replace(/\s*```$/, "");

  return cleanHtml;
};

/**
 * Generates an educational image using the Nano Banana model.
 */
export const generateLessonImage = async (imagePrompt: string): Promise<string | undefined> => {
  const ai = getAiClient();

  const refinedPrompt = `Technical architecture diagram, blueprint style, isometric view or flat schematic. Detailed representation of: ${imagePrompt}. White background, corporate blue/slate color palette, clean vector lines, high resolution, engineering drawing style.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: {
        parts: [{ text: refinedPrompt }]
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Image generation failed:", error);
    return undefined;
  }

  return undefined;
};

