                                    >
                                       {generatingImageId === activeLesson.id ? <><div className="w-3 h-3 border-2 border-indigo-600 border-t-transparent rounded-full animate-spin"/> <span>Criando...</span></> : <><WandIcon /> <span>Gerar com Nano Banana</span></>}
