  const textPrompt = `Você é um Principal Technical Writer.

  INPUT DE DADOS (HIERARQUIA CRÍTICA):
  1. O CONTEÚDO BRUTO (A "AULA"): Está dentro dos arquivos anexados. Encontre o trecho correspondente ao tópico "${lessonTitle}". ESSE É SEU TEXTO BASE.
  2. VALIDAÇÃO (ANTI-ALUCINAÇÃO): Use a ferramenta de busca na URL ${course.docUrl || 'oficial'} para verificar se os comandos/conceitos do texto base ainda são válidos hoje.

  TAREFA:
  Transforme o texto bruto (dos arquivos) em um ARTIGO TÉCNICO PROFUNDO (Estilo Wiki).
  - Se o texto base for curto, EXPANDA usando os conceitos encontrados na busca (explique o "Porquê", a Arquitetura).
  - Se o texto base for longo, FORMATE para leitura web (Wiki), mantendo a densidade técnica.

  CONTEXTO:
  Curso: "${course.title}"
  Público: "${course.targetAudience}"

  FORMATO (HTML + TAILWIND):
  - Use <h2>, <h3>, <pre><code>.
  - Explique arquitetura (First Principles).
  - Inclua seção de referências (Link da URL).

  Gere apenas o HTML do conteúdo (dentro de uma div).`;

  const parts: any[] = [{ text: textPrompt }];

  course.contextFiles.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const response = await ai.models.generateContent({
