        <aside id="sidebar" class="absolute inset-y-0 left-0 z-20 w-80 bg-slate-50 border-r border-slate-200 flex flex-col sidebar-closed md:relative md:transform-none shadow-xl md:shadow-none">
            <div class="p-4 border-b border-slate-200 bg-slate-100/50 flex items-center justify-between md:justify-start">
