    <script>
        const courseData = ${dataJson};

        // --- MOCK LMS API (Correção para o erro de Cross-Origin) ---
        // Implementação robusta fornecida na referência para permitir execução local e prevenir bloqueios
        window.API = {
            LMSInitialize: function(param) {
                console.log("[LMS Mock] LMSInitialize chamado.");
                return "true";
            },
            LMSFinish: function(param) {
                console.log("[LMS Mock] LMSFinish chamado.");
                return "true";
            },
            LMSGetValue: function(element) {
                console.log("[LMS Mock] LMSGetValue: " + element);
                if (element === "cmi.core.student_id") return "TEST_USER_ID";
                if (element === "cmi.core.student_name") return "Teste Utilizador";
                return "";
            },
            LMSSetValue: function(element, value) {
                console.log("[LMS Mock] LMSSetValue: " + element + " = " + value);
                return "true";
            },
            LMSCommit: function(param) {
                console.log("[LMS Mock] LMSCommit chamado.");
                return "true";
            },
            LMSGetLastError: function() { return "0"; },
            LMSGetErrorString: function(code) { return "No error"; },
            LMSGetDiagnostic: function(code) { return "No error"; }
        };

        // --- SCORM LOGIC ---
        const scorm = {
            api: null, version: null, startTime: new Date(),
            init: function() {
                try {
                    let parentWin = window.parent;
                    // First try to find API in parent
                    if (parentWin && parentWin.API_1484_11) { 
                        this.api = parentWin.API_1484_11; 
                        this.version = "2004"; 
                        this.api.Initialize(""); 
                        console.log("SCORM 2004 API Found");
                    } 
                    else if (parentWin && parentWin.API) { 
                        this.api = parentWin.API; 
                        this.version = "1.2"; 
                        this.api.LMSInitialize(""); 
                        console.log("SCORM 1.2 API Found");
                    }
                    else { 
                        // FALLBACK TO MOCK API (Self-contained mode)
                        console.log("No LMS API found. Using Local Mock API for standalone mode.");
                        this.api = window.API; // Use the local mock
                        this.version = "1.2"; // Assume 1.2 for mock
                        this.api.LMSInitialize("");
                    }

                    if(this.api) this.setStatus("incomplete");
                } catch (e) { 
                    console.warn("SCORM Init Error:", e); 
                    // Fallback purely local
                    this.api = window.API;
                }
            },
            setStatus: function(s) { if(!this.api) return; this.version==="2004" ? this.api.SetValue("cmi.completion_status", s==='passed'?'completed':s) : this.api.LMSSetValue("cmi.core.lesson_status", s); this.commit(); },
            setBookmark: function(l) { if(!this.api) return; this.version==="2004" ? this.api.SetValue("cmi.location", l) : this.api.LMSSetValue("cmi.core.lesson_location", l); this.commit(); },
            getBookmark: function() { if(!this.api) return null; return this.version==="2004" ? this.api.GetValue("cmi.location") : this.api.LMSGetValue("cmi.core.lesson_location"); },
            commit: function() { if(this.api) this.version==="2004" ? this.api.Commit("") : this.api.LMSCommit(""); },
            finish: function() { if(this.api) this.version==="2004" ? this.api.Terminate("") : this.api.LMSFinish(""); }
        };

        let currentSlide = 0;

        // --- UI LOGIC ---
        function initApp() {
            scorm.init();
            renderSidebar();

            const bookmark = scorm.getBookmark();
            if (bookmark && parseInt(bookmark) > 0) currentSlide = parseInt(bookmark);

            renderSlide(currentSlide);
            setupMobileMenu();

            // Remove Loader
            setTimeout(() => {
                const loader = document.getElementById('app-loader');
                loader.style.opacity = '0';
                setTimeout(() => loader.remove(), 500);
            }, 800);
        }

        function renderSidebar() {
            const toc = document.getElementById('toc');
            let currentModule = null;

            courseData.forEach((item, index) => {
                // Check if new module header is needed
                if (item.module !== currentModule) {
                    currentModule = item.module;
                    const modHeader = document.createElement('div');
                    modHeader.className = "px-3 py-2 mt-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider";
                    modHeader.innerText = currentModule || "Geral";
                    toc.appendChild(modHeader);
                }

                // Lesson Item
                const btn = document.createElement('button');
                btn.id = "toc-item-" + index;
                btn.className = "w-full text-left px-3 py-2 rounded-md text-sm transition-all flex items-start gap-3 text-slate-600 hover:bg-slate-200 hover:text-slate-900 border border-transparent";
                btn.onclick = () => {
                    renderSlide(index);
                    if(window.innerWidth < 768) toggleSidebar();
                };

                const icon = document.createElement('i');
                icon.className = (item.type === 'final' ? "fas fa-flag-checkered" : "fas fa-file-alt") + " w-4 mt-0.5 text-slate-400";

                const text = document.createElement('span');
                text.className = "leading-tight";
                text.innerText = item.title;

                btn.appendChild(icon);
                btn.appendChild(text);
                toc.appendChild(btn);
            });
        }

        function renderSlide(index) {
            currentSlide = index;
            const container = document.getElementById("content-area");
            const data = courseData[index];

            // Animation reset
            container.classList.remove("fade-enter");
            void container.offsetWidth; 
            container.classList.add("fade-enter");

            container.innerHTML = data.content;
            document.getElementById("scroll-container").scrollTop = 0;

            // Mermaid Re-init
            if(window.mermaid) {
                setTimeout(() => { mermaid.init(undefined, document.querySelectorAll('.mermaid')); }, 100);
            }

            updateControls(index, data.type);
            updateProgress();
            updateSidebarActiveState(index);
            scorm.setBookmark(index);
        }

        function updateSidebarActiveState(index) {
            document.querySelectorAll('#toc button').forEach(b => {
                b.classList.remove('active-lesson');
                b.classList.add('text-slate-600');
                b.classList.remove('bg-white', 'shadow-sm', 'border-slate-200');
            });
            const active = document.getElementById("toc-item-" + index);
            if(active) {
                active.classList.add('active-lesson');
                active.classList.add('bg-white', 'shadow-sm', 'border-slate-200');
                active.classList.remove('text-slate-600');
                active.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
            }
        }

        function updateControls(index, type) {
            document.getElementById("slide-indicator").innerText = (index + 1) + " / " + courseData.length;
            document.getElementById("btn-prev").disabled = index === 0;
            const btnNext = document.getElementById("btn-next");
            if (type === "final") {
                btnNext.style.display = "none";
                scorm.setStatus("passed");
            } else { 
                btnNext.style.display = "flex"; 
                btnNext.disabled = index === courseData.length - 1; 
            }
        }

        function updateProgress() {
            const p = ((currentSlide + 1) / courseData.length) * 100;
            document.getElementById("progress-bar").style.width = p + "%";
            document.getElementById("progress-text").innerText = Math.round(p) + "%";
        }

        // --- Sidebar Toggle for Mobile ---
        function toggleSidebar() {
            const sidebar = document.getElementById('sidebar');
            const overlay = document.getElementById('sidebar-overlay');
            const isClosed = sidebar.classList.contains('sidebar-closed');

            if (isClosed) {
                sidebar.classList.remove('sidebar-closed');
                overlay.classList.remove('hidden');
                setTimeout(() => overlay.classList.remove('opacity-0'), 10);
            } else {
                sidebar.classList.add('sidebar-closed');
                overlay.classList.add('opacity-0');
                setTimeout(() => overlay.classList.add('hidden'), 300);
            }
        }

        function setupMobileMenu() {
            // Ensure sidebar resets on resize
            window.addEventListener('resize', () => {
                if(window.innerWidth >= 768) {
                    document.getElementById('sidebar').classList.remove('sidebar-closed');
                    document.getElementById('sidebar-overlay').classList.add('hidden');
                } else {
                    document.getElementById('sidebar').classList.add('sidebar-closed');
                }
            });
        }

        function nextSlide() { if (currentSlide < courseData.length - 1) renderSlide(currentSlide + 1); }
        function prevSlide() { if (currentSlide > 0) renderSlide(currentSlide - 1); }
        function exitCourse() { scorm.finish(); window.close(); }

        window.onload = initApp;
    </script>
</body>
</html>`;

  // --- Render Navigation ---
  const handleLessonSelect = (lesson: Lesson) => {
    setActiveLessonId(lesson.id);
    if (!lesson.content && course) {
      fetchLessonContent(lesson, course);
    }
  };

  const getActiveLesson = () => {
    if (!course) return null;
    for (const mod of course.modules) {
      for (const les of mod.lessons) {
        if (les.id === activeLessonId) return les;
      }
    }
    return null;
  };

  const activeLesson = getActiveLesson();

  // --- View: Initial Form (Wizard Style) ---
  if (!course) {
    return (
      <div className="flex flex-col min-h-screen bg-slate-50 font-sans text-slate-900 selection:bg-blue-100 selection:text-blue-700">
         {/* Simple Navbar */}
         <div className="w-full bg-white border-b border-slate-200 py-4 px-8 flex justify-between items-center">
            <div className="flex items-center gap-2 text-indigo-600 font-bold text-xl tracking-tight">
               <SparklesIcon className="w-6 h-6" />
               <span>ScormGenAI</span>
            </div>
            <div className="text-sm text-slate-500">v1.1.0</div>
         </div>

         {/* Wizard Content */}
         <div className="flex-1 flex flex-col items-center justify-center p-6">
            <div className="w-full max-w-4xl bg-white rounded-2xl shadow-xl border border-slate-100 overflow-hidden">
               <div className="p-1 bg-gradient-to-r from-blue-500 via-indigo-500 to-purple-500"></div>
               <div className="p-8 md:p-12">
                  <div className="text-center mb-10">
                    <h1 className="text-3xl md:text-4xl font-bold text-slate-900 mb-4 tracking-tight">Criar Novo Curso</h1>
                    <p className="text-lg text-slate-600 max-w-xl mx-auto">
                      Preencha os detalhes abaixo para gerar um curso SCORM baseado exclusivamente em suas referências.
                    </p>
                  </div>

                  <form onSubmit={handleCreateCourse} className="space-y-8">

                     <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        {/* Left Column */}
                        <div className="space-y-6">
                            <div className="space-y-3">
                                <label htmlFor="objective" className="block text-sm font-bold text-slate-800 uppercase tracking-wide">1. Objetivo Geral do Curso</label>
                                <textarea 
                                  id="objective" 
                                  value={courseObjective} 
                                  onChange={(e) => setCourseObjective(e.target.value)} 
                                  placeholder="Ex: Ensinar os fundamentos de Cloud Computing para analistas de negócios..." 
                                  className="w-full p-4 rounded-xl bg-slate-50 border border-slate-200 focus:bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none resize-none h-32"
                                  disabled={loading}
                                />
                            </div>

                            <div className="space-y-3">
                               <label htmlFor="target" className="block text-sm font-bold text-slate-800 uppercase tracking-wide">2. Público-Alvo</label>
                               <input 
                                 type="text" 
                                 id="target" 
                                 value={targetAudience} 
                                 onChange={(e) => setTargetAudience(e.target.value)} 
                                 placeholder="Ex: Desenvolvedores Sênior, Gestores..." 
                                 className="w-full p-3 rounded-xl bg-slate-50 border border-slate-200 focus:bg-white focus:border-indigo-500 outline-none transition-all"
                                 disabled={loading}
                               />
                            </div>
                        </div>

                        {/* Right Column */}
                        <div className="space-y-6">
                             <div className="space-y-3">
                                <label htmlFor="structure" className="block text-sm font-bold text-slate-800 uppercase tracking-wide">3. Estrutura do Curso (Módulos/Tópicos)</label>
                                <textarea 
                                  id="structure" 
                                  value={courseStructure} 
                                  onChange={(e) => setCourseStructure(e.target.value)} 
                                  placeholder="Ex: 
- Módulo 1: Introdução
- Módulo 2: Arquitetura
- Módulo 3: Prática..." 
                                  className="w-full p-4 rounded-xl bg-slate-50 border border-slate-200 focus:bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none resize-none h-32"
                                  disabled={loading}
                                />
                            </div>

                             <div className="space-y-3">
                               <label htmlFor="docUrl" className="block text-sm font-bold text-slate-800 uppercase tracking-wide flex items-center gap-2"><LinkIcon className="w-4 h-4 text-blue-500" /> 5. Fonte Oficial (Validação via URL)</label>
                               <input 
                                 type="url" 
                                 id="docUrl" 
                                 value={docUrl} 
                                 onChange={(e) => setDocUrl(e.target.value)} 
                                 placeholder="https://docs.exemplo.com..." 
                                 className="w-full p-3 rounded-xl bg-slate-50 border border-slate-200 focus:bg-white focus:border-indigo-500 outline-none transition-all"
                                 disabled={loading}
                               />
                            </div>
                        </div>
                     </div>

                     <div className="space-y-4 pt-4 border-t border-slate-100">
                        <label className="block text-sm font-bold text-slate-800 uppercase tracking-wide">4. Conteúdo Base / Material Didático (Texto Completo da Aula)</label>
                        <div 
                          className={`border-2 border-dashed rounded-xl p-8 text-center transition-all cursor-pointer group ${loading ? 'bg-slate-50 border-slate-200 opacity-50' : 'border-slate-300 hover:border-indigo-400 hover:bg-indigo-50'}`} 
                          onClick={() => !loading && fileInputRef.current?.click()}
                        >
                          <input type="file" ref={fileInputRef} className="hidden" multiple accept="application/pdf,image/*,text/plain" onChange={handleFileChange} />
                          <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-3 group-hover:scale-110 transition-transform">
                             <UploadIcon className="w-6 h-6" />
                          </div>
                          <p className="text-slate-900 font-medium">Faça upload de Apostilas, Roteiros ou PDFs Completos</p>
                          <p className="text-sm text-slate-500">Importe o conteúdo completo. A IA usará este texto como a fonte principal do curso.</p>
                        </div>
                        {files.length > 0 && (
                          <div className="flex flex-wrap gap-2">
                            {files.map((file, idx) => (
                              <div key={idx} className="flex items-center gap-2 bg-indigo-50 text-indigo-700 px-3 py-1.5 rounded-lg border border-indigo-100 text-sm font-medium">
                                <span className="truncate max-w-[150px]">{file.name}</span>
                                <button type="button" onClick={(e) => {e.stopPropagation(); removeFile(idx);}} className="text-indigo-400 hover:text-indigo-600"><TrashIcon /></button>
                              </div>
                            ))}
                          </div>
                        )}
                     </div>

                     <button 
                       type="submit" 
                       disabled={loading || !courseObjective.trim()} 
                       className={`w-full py-4 rounded-xl font-bold text-lg shadow-lg hover:shadow-xl hover:-translate-y-0.5 transition-all flex items-center justify-center gap-2 ${loading ? 'bg-slate-300 text-slate-500 cursor-not-allowed' : 'bg-gradient-to-r from-indigo-600 to-blue-600 text-white'}`}
                     >
                       {loading ? (
                         <><div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> <span>Lendo Material e Validando na URL...</span></>
                       ) : (
                         <><SparklesIcon /> <span>Gerar Curso</span></>
                       )}
                     </button>
                  </form>
               </div>
            </div>

            <div className="mt-8 text-center text-slate-400 text-sm">
               Powered by Google Gemini Nano • Real-time Docs Reading
