           </div>

           {/* Editor Actions */}
           <div className="flex items-center gap-2">
              {activeLesson && (
                <>
                  {/* Media Insert Group */}
                  <div className="flex bg-slate-100 rounded-lg p-1 mr-2 border border-slate-200">
                      <button 
                        onClick={() => setMediaType(mediaType === 'video' ? null : 'video')} 
