                         <VideoIcon />
                      </button>
                      <button 
                        onClick={() => setMediaType(mediaType === 'drive' ? null : 'drive')} 
                        className={`p-1.5 rounded-md transition-all ${mediaType === 'drive' ? 'bg-white shadow text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}
