    <script>
        const courseData = ${dataJson};

        // --- MOCK LMS API (Robust implementation for local testing) ---
        window.API = {
            LMSInitialize: function(param) { console.log("[LMS Mock] LMSInitialize"); return "true"; },
            LMSFinish: function(param) { console.log("[LMS Mock] LMSFinish"); return "true"; },
            LMSGetValue: function(element) { 
                console.log("[LMS Mock] LMSGetValue: " + element);
                if (element === "cmi.core.student_id") return "TEST_USER_ID";
                if (element === "cmi.core.student_name") return "Teste Utilizador";
                return "";
            },
            LMSSetValue: function(element, value) { console.log("[LMS Mock] LMSSetValue: " + element + " = " + value); return "true"; },
            LMSCommit: function(param) { console.log("[LMS Mock] LMSCommit"); return "true"; },
            LMSGetLastError: function() { return "0"; },
            LMSGetErrorString: function(code) { return "No error"; },
            LMSGetDiagnostic: function(code) { return "No error"; }
        };

        // --- SCORM LOGIC ---
        const scorm = {
            api: null, version: null, startTime: new Date(),
            init: function() {
                try {
                    let parentWin = window.parent;
                    if (parentWin && parentWin.API_1484_11) { 
                        this.api = parentWin.API_1484_11; this.version = "2004"; this.api.Initialize(""); console.log("SCORM 2004 Found");
                    } else if (parentWin && parentWin.API) { 
                        this.api = parentWin.API; this.version = "1.2"; this.api.LMSInitialize(""); console.log("SCORM 1.2 Found");
                    } else { 
                        console.log("Using Local Mock API"); this.api = window.API; this.version = "1.2"; this.api.LMSInitialize("");
                    }
                    if(this.api) this.setStatus("incomplete");
                } catch (e) { console.warn("SCORM Init Error:", e); this.api = window.API; }
            },
            setStatus: function(s) { if(!this.api) return; this.version==="2004" ? this.api.SetValue("cmi.completion_status", s==='passed'?'completed':s) : this.api.LMSSetValue("cmi.core.lesson_status", s); this.commit(); },
            setBookmark: function(l) { if(!this.api) return; this.version==="2004" ? this.api.SetValue("cmi.location", l) : this.api.LMSSetValue("cmi.core.lesson_location", l); this.commit(); },
            getBookmark: function() { if(!this.api) return null; return this.version==="2004" ? this.api.GetValue("cmi.location") : this.api.LMSGetValue("cmi.core.lesson_location"); },
            commit: function() { if(this.api) this.version==="2004" ? this.api.Commit("") : this.api.LMSCommit(""); },
            finish: function() { if(this.api) this.version==="2004" ? this.api.Terminate("") : this.api.LMSFinish(""); }
        };

        let currentSlide = 0;

        // --- UI LOGIC ---
        function initApp() {
            scorm.init();
            renderSidebar();

            const bookmark = scorm.getBookmark();
            if (bookmark && parseInt(bookmark) > 0) currentSlide = parseInt(bookmark);

            renderSlide(currentSlide);
            setupMobileMenu();

            setTimeout(() => {
                const loader = document.getElementById('app-loader');
                loader.style.opacity = '0';
                setTimeout(() => loader.remove(), 500);
            }, 800);
        }

        function renderSidebar() {
            const toc = document.getElementById('toc');
            let currentModule = null;

            courseData.forEach((item, index) => {
                if (item.module !== currentModule) {
                    currentModule = item.module;
                    const modHeader = document.createElement('div');
                    modHeader.className = "px-3 py-2 mt-4 text-[11px] font-bold text-slate-400 uppercase tracking-wider";
                    modHeader.innerText = currentModule || "Geral";
                    toc.appendChild(modHeader);
                }

                const btn = document.createElement('button');
                btn.id = "toc-item-" + index;
                btn.className = "w-full text-left px-3 py-2 rounded-md text-sm transition-all flex items-start gap-3 text-slate-600 hover:bg-slate-200 hover:text-slate-900 border border-transparent";
                btn.onclick = () => { renderSlide(index); if(window.innerWidth < 768) toggleSidebar(); };

                const icon = document.createElement('i');
                icon.className = (item.type === 'final' ? "fas fa-flag-checkered" : "fas fa-file-alt") + " w-4 mt-0.5 text-slate-400";

                const text = document.createElement('span');
                text.className = "leading-tight";
                text.innerText = item.title;

                btn.appendChild(icon);
                btn.appendChild(text);
                toc.appendChild(btn);
            });
        }

        function renderSlide(index) {
            currentSlide = index;
            const container = document.getElementById("content-area");
            const data = courseData[index];

            container.classList.remove("fade-enter");
            void container.offsetWidth; 
            container.classList.add("fade-enter");

            container.innerHTML = data.content;
            document.getElementById("scroll-container").scrollTop = 0;

            if(window.mermaid) { setTimeout(() => { mermaid.init(undefined, document.querySelectorAll('.mermaid')); }, 100); }

            updateControls(index, data.type);
            updateProgress();
            updateSidebarActiveState(index);
            scorm.setBookmark(index);
        }

        function updateSidebarActiveState(index) {
            document.querySelectorAll('#toc button').forEach(b => {
                b.classList.remove('active-lesson');
                b.classList.add('text-slate-600');
                b.classList.remove('bg-white', 'shadow-sm', 'border-slate-200');
            });
            const active = document.getElementById("toc-item-" + index);
            if(active) {
                active.classList.add('active-lesson');
                active.classList.add('bg-white', 'shadow-sm', 'border-slate-200');
                active.classList.remove('text-slate-600');
                active.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
            }
        }

        function updateControls(index, type) {
            document.getElementById("slide-indicator").innerText = (index + 1) + " / " + courseData.length;
            document.getElementById("btn-prev").disabled = index === 0;
            const btnNext = document.getElementById("btn-next");
            if (type === "final") {
                btnNext.style.display = "none";
                scorm.setStatus("passed");
            } else { 
                btnNext.style.display = "flex"; 
                btnNext.disabled = index === courseData.length - 1; 
            }
        }

        function updateProgress() {
            const p = ((currentSlide + 1) / courseData.length) * 100;
            document.getElementById("progress-bar").style.width = p + "%";
            document.getElementById("progress-text").innerText = Math.round(p) + "%";
        }

        function toggleSidebar() {
            const sidebar = document.getElementById('sidebar');
            const overlay = document.getElementById('sidebar-overlay');
            const isClosed = sidebar.classList.contains('sidebar-closed');
            if (isClosed) {
                sidebar.classList.remove('sidebar-closed');
                overlay.classList.remove('hidden');
                setTimeout(() => overlay.classList.remove('opacity-0'), 10);
            } else {
                sidebar.classList.add('sidebar-closed');
                overlay.classList.add('opacity-0');
                setTimeout(() => overlay.classList.add('hidden'), 300);
            }
        }

        function setupMobileMenu() {
            window.addEventListener('resize', () => {
                if(window.innerWidth >= 768) {
                    document.getElementById('sidebar').classList.remove('sidebar-closed');
                    document.getElementById('sidebar-overlay').classList.add('hidden');
                } else {
                    document.getElementById('sidebar').classList.add('sidebar-closed');
                }
            });
        }

        function nextSlide() { if (currentSlide < courseData.length - 1) renderSlide(currentSlide + 1); }
        function prevSlide() { if (currentSlide > 0) renderSlide(currentSlide - 1); }
        function exitCourse() { scorm.finish(); window.close(); }

        window.onload = initApp;
    </script>
</body>
</html>`;

import { GoogleGenAI, Type } from "@google/genai";
import { Course, Module, Lesson, FileContext } from "../types";

const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean up JSON string if the model adds backticks
const cleanJson = (text: string) => {
  return text.replace(/^```json\s*/, "").replace(/\s*```$/, "");
};

// Helper to extract raw base64 from data URI if present
const getBase64Data = (dataUri: string) => {
  return dataUri.includes(',') ? dataUri.split(',')[1] : dataUri;
};

// Helper to clean HTML markdown
const cleanHtmlResponse = (text: string) => {
  return text.replace(/^```html\s*/, "").replace(/^```\s*/, "").replace(/\s*```$/, "");
};

/**
 * Generates a course outline based on provided objective, structure, files, and audience.
 */
export const generateCourseOutline = async (
  courseObjective: string,
  userStructure: string,
  targetAudience: string,
  files: FileContext[],
  docUrl?: string,
  language: string = 'Português do Brasil'
): Promise<Course> => {
  const ai = getAiClient();

  const textPrompt = `Atue como um Arquiteto de Soluções e Tech Lead.

  METODOLOGIA HÍBRIDA (ARQUIVOS + REAL-TIME):
  1. FONTE PRIMÁRIA (O TEXTO DA AULA): Os arquivos anexados contêm o CONTEÚDO COMPLETO e o roteiro da aula. Você deve estruturar o curso baseado no texto contido nestes arquivos.
  2. FONTE DE VALIDAÇÃO (URL): O usuário forneceu a URL ${docUrl || 'Nenhuma'}. Use a ferramenta de busca para LER esta página e GARANTIR que o conteúdo dos arquivos não está obsoleto.

  OBJETIVO DO CURSO/WIKI:
  ${courseObjective}

  ESTRUTURA SUGERIDA:
  ${userStructure ? userStructure : "Extraia a estrutura lógica (Tópicos/Capítulos) diretamente do texto dos arquivos."}

  PÚBLICO-ALVO:
  ${targetAudience}

  INSTRUÇÕES DE SAÍDA:
  1. A saída deve estar estritamente em ${language}.
  2. Organize em Módulos e Lições.
  3. Para cada lição, crie um 'imagePrompt' para um diagrama de arquitetura técnica.`;

  const parts: any[] = [{ text: textPrompt }];

  files.forEach(file => {
    parts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          modules: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                lessons: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      title: { type: Type.STRING },
                      imagePrompt: { type: Type.STRING, description: "Descrição técnica detalhada para diagrama de arquitetura." }
                    },
                    required: ["title", "imagePrompt"]
                  }
                }
              },
              required: ["title", "lessons"]
            }
          }
        },
        required: ["title", "description", "modules"]
      }
    }
  });

  const rawText = response.text || "{}";
  const data = JSON.parse(cleanJson(rawText));

  const course: Course = {
    id: crypto.randomUUID(),
    title: data.title,
    description: data.description,
    language: language,
    targetAudience: targetAudience,
    contextFiles: files,
    docUrl: docUrl,
    modules: data.modules.map((m: any) => ({
      id: crypto.randomUUID(),
      title: m.title,
      lessons: m.lessons.map((l: any) => ({
        id: crypto.randomUUID(),
        title: l.title,
        imagePrompt: l.imagePrompt,
        content: "", 
      }))
    }))
  };

  return course;
};

/**
 * 2-STEP GENERATION PROCESS
 * 1. Agent Drafter: Creates content from files.
 * 2. Agent Reviewer: Validates against files and refines didactic structure.
 */
export const generateLessonContent = async (
  lessonTitle: string, 
  course: Course,
  onStatusUpdate?: (status: string) => void
): Promise<string> => {
  const ai = getAiClient();

  // --- AGENT 1: DRAFTER ---
  if (onStatusUpdate) onStatusUpdate("Agente 1: Rascunhando conteúdo base...");

  const drafterPrompt = `ROLE: Technical Writer Sênior.

  TAREFA: Escrever o PRIMEIRO RASCUNHO para a lição: "${lessonTitle}".

  FONTE DE DADOS (HIERARQUIA):
  1. Texto Base (FONTE DA VERDADE): Use estritamente os arquivos anexados pelo usuário. Encontre o trecho relevante no material.
  2. Validação (ANTI-ALUCINAÇÃO): Use a ferramenta de busca (Google Search) na URL ${course.docUrl || 'oficial'} APENAS para verificar se comandos ou versões não estão depreciados.

  ESTILO:
  - Artigo Técnico (Wiki Style).
  - Profundidade Técnica: Explique a arquitetura e os "Porquês" (First Principles).
  - Formatação: HTML Válido com classes Tailwind CSS.

  SAÍDA ESPERADA:
  Conteúdo HTML bruto do rascunho da aula.`;

  const drafterParts: any[] = [{ text: drafterPrompt }];
  course.contextFiles.forEach(file => {
    drafterParts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const draftResponse = await ai.models.generateContent({
    model: "gemini-3-flash-preview", // Flash for speed in drafting
    contents: { parts: drafterParts },
    config: { tools: [{ googleSearch: {} }] }
  });

  const draftContent = cleanHtmlResponse(draftResponse.text || "");

  // --- AGENT 2: REVIEWER PROFESSOR ---
  if (onStatusUpdate) onStatusUpdate("Agente 2 (Professor): Auditando e corrigindo conformidade...");

  const reviewerPrompt = `ROLE: PROFESSOR ESPECIALISTA e AUDITOR DE CONTEÚDO (QA).

  SUA MISSÃO CRÍTICA:
  Você deve revisar o rascunho abaixo para garantir CONFORMIDADE TOTAL com o Material Didático Original (Arquivos Anexados).

  ENTRADAS:
  1. MATERIAL ORIGINAL: (Ver anexos).
  2. RASCUNHO GERADO PELO AGENTE 1: 
  """
  ${draftContent}
  """

  LISTA DE VERIFICAÇÃO (AUDITORIA):
  1. CONFORMIDADE: O rascunho inventou algo que não está no material base? Se sim, REMOVA ou CORRIJA para alinhar estritamente com a fonte. O material original tem autoridade final sobre o escopo.
  2. DIDÁTICA: O conteúdo explica o "Porquê"? Se estiver muito "passo-a-passo" sem teoria, ADICIONE explicações teóricas baseadas no material original.
  3. CLAREZA: O formato está legível? Melhore a estrutura HTML se necessário.

  RESTRIÇÃO DE SAÍDA (SILENT MODE):
  - Retorne APENAS o HTML FINAL, polido e auditado.
  - NÃO adicione comentários como "Aqui está a versão corrigida".
  - NÃO explique o que você mudou.
  - O usuário final não deve saber que houve uma revisão, apenas receber o conteúdo perfeito.`;

  const reviewerParts: any[] = [{ text: reviewerPrompt }];
  // Re-attach files so the reviewer can audit against them
  course.contextFiles.forEach(file => {
    reviewerParts.push({
      inlineData: {
        mimeType: file.mimeType,
        data: getBase64Data(file.data)
      }
    });
  });

  const finalResponse = await ai.models.generateContent({
    model: "gemini-3-pro-preview", // Pro for deep reasoning/auditing
    contents: { parts: reviewerParts },
    config: { 
      thinkingConfig: { thinkingBudget: 2048 } // Budget for auditing logic
    }
  });

  return cleanHtmlResponse(finalResponse.text || "");
};

/**
 * Generates an educational image using the Nano Banana model.
 */
export const generateLessonImage = async (imagePrompt: string): Promise<string | undefined> => {
  const ai = getAiClient();
  const refinedPrompt = `Technical architecture diagram, blueprint style, isometric view or flat schematic. Detailed representation of: ${imagePrompt}. White background, corporate blue/slate color palette, clean vector lines, high resolution, engineering drawing style.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: [{ text: refinedPrompt }] }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Image generation failed:", error);
    return undefined;
  }
  return undefined;
};

